INSERT INTO `Photos` (`id`, `title`, `details`, `categoryName`, `image`) VALUES
(2, 'قصف برج مشتهى', 'تعمد الاحتلال استخدام منهجية قصف الأبراج والمجمعات السكنية أثر بشكل كبير على نزوح الألاف نحو المجهول بلا مأوى', 'ما بعد القصف', '1775779808_برج مشتهى.jpg.webp'),
(3, 'وجع وتعب في رحلة النزوح', 'نزوح آلاف السكان من مدينة غزة إلى جنوب الوادي بعد تهديد مستمر من الإحتلال الإسرائيلي.', 'رحلة النزوح', '1776075285_نزوح١.jpeg'),
(4, 'دموعنا تودعهم ...... وفخرنا يُخلدهم', 'آخر عناق وآخر وداع في وسط وجعٍ مؤلم محفور بقلوبٍ بريئة', 'سير الشهداء', '1776107508_شهداء١.jpeg'),
(5, 'في النزوح نحمل بيوتنا في قلوبنا', 'عائلة غزاوية تحمل بيتها وذكرياتها في قلوب أنهكتها الحرب والإبادة.', 'رحلة النزوح', '1776107781_نزوح٢.jpeg'),
(6, 'من بين الألم .... يولد الصمود', 'اصابات وجروح لمدنين لا ذنب لهم سوى حبهم لوطنهم وتمسكهم فيه.', 'ما بين الحياة والموت', '1776107940_اصابات١.jpeg'),
(7, 'وداعهم موجع .... لكن ذكراهم قوية', 'وداع الحبيب والرفيق بدموع وقلب مكسور لن يزول منه الألم', 'سير الشهداء', '1776108203_شهداء٢.jpeg'),
(8, 'بين التكبيرات....حكايات لا تُروى', 'أطفال لاذنب لهم سوى انهم في وسط إبادة لا تفرق بين الصغير والكبير.', 'سير الشهداء', '1776108479_شهداء٣.jpeg'),
(9, 'وجع في الكرامة ', 'الجوع ليس ألماً في المعدة فقط بل إهانة وكسر للقلوب البشرية.', 'صرخات الجوع', '1776108607_مجاعة١.jpeg'),
(10, 'بيوت كانت مليئة بالحياة أصبحت صامتة', 'من شوارع ومدن كانت مليئة بالحياة الى اماكن صامتة لا يملؤها سوى الغبار والدمار.', 'ما بعد القصف', '1776111059_قصف١.jpeg'),
(11, 'رحلوا وبقي الأثر في القلب لا يزول', 'امرأة عاجزة تقف بين جثامين أحبابها لا تعرف من تودع أولاً بقلب محطم لايحمل سوى الوجع.', 'سير الشهداء', '1776111310_شهداء٤.jpeg'),
(12, 'رغم التعب.....نواصل الطريق', 'من حياة مليئة بالكرامة إلى إهانة ومذلة للحصول على أساسيات الحياة', 'رحلة النزوح', '1776111645_نزوح٣.jpeg'),
(13, 'في عمق المعاناة .... يولد الأمل', 'تحولت ألوان الحياة إلى رماد وحزن لا يمكن قياسه.', 'رحلة النزوح', '1776111812_نزوح٤.jpeg'),
(14, 'المجاعة لا تسرق الطعام فقط ... بل الأمل أيضاً ', 'لم تسرق الحرب طعامهم فقط بل سرقت حياة كاملة حرمتهم التعليم والطفولة.', 'صرخات الجوع', '1776112068_مجاعة٢.jpeg'),
(15, 'التدمير يمحو المكان .... لكنه لا يمحو الأثر', 'يجلس أمام منزله المدمر يحمل في ذاكرته اصوات وحياة لا يمكن نسيانها.', 'ما بعد القصف', '1776112204_قصف٢.jpeg'),
(16, 'الركام ليس حجارة فقط ....بل أعماراً انهارت', 'في القصف ليست الحجارة التي تتساقط فقط بل أشخاص رحلوا إلى حياة ثانية.', 'ما بعد القصف', '1776112356_قصف٣.jpeg'),
(17, 'رغم القصف .....يبقى الأمل يقاوم', 'من بين الركام تُقام الحياة لتستمر رغم الوجع والفقد.', 'ما بعد القصف', '1776112498_قصف٤.jpeg'),
(18, 'رحلوا .... لكنهم علمونا معنى البقاء', 'يقف الطفل البرئ ليُلقي نظرة الوداع ليرتجل بعدها ويطوي صفحة الطفولة.', 'سير الشهداء', '1776112643_شهداء٥.jpeg'),
(19, 'كل جرح يحمل درساً .... وإن كان موجعاً', 'أطفال أبرياء وجدوا أنفسهم في وسط ركام أنهك أجسادهم بالشظايا والجروح.', 'ما بين الحياة والموت', '1776112845_اصابات٢.jpeg'),
(20, 'الألم يمر.....لكن أثره لا يخفى', 'فتاة في عمر الزهور فقدت أطرافها وهي لم تحقق أحلامها بعد.....', 'ما بين الحياة والموت', '1776215527_صورة فتاة.png'),
(21, 'التدمير نهاية مكان .... وبداية حزن طويل', 'منطقة سكنية كاملة انهالت وأصبحت ركام تحمل بين ركامها أصحابها وذكرياتهم', 'ما بعد القصف', '1776215702_قصف٥.jpeg'),
(22, 'التدمير يسرق البيوت ....ويترك الذكريات تحت الركام ', 'ذكريات كاملة دُفنت تحت الركام وعائلات بلا مأوى.....', 'ما بعد القصف', '1776216215_قصف٦.jpeg'),
(23, 'القصف لا يُفرّق....لكنه يوجع الجميع ', 'يبحثون بين الركام على أحباب ذهبوا ولن يعودوا.....', 'ما بعد القصف', '1776215961_قصف٧.jpeg'),
(24, 'ما بين لحظة وأخرى يتغير كل شيء', 'فجأة تحولت الحياة بكافة ألوانها إلى لون رمادي يحمل الركام لا شيء غيره', 'ما بعد القصف', '1776216377_قصف٨.jpeg'),
(25, 'بين الدخان والغبار....تختنق الأحلام', 'صورة المكان هكذا مؤلمة فكيف كانت على من شاهد وسمع صوت التدمير', 'ما بعد القصف', '1776216486_قصف٩.jpeg'),
(26, 'بين الحجارة والغبار....تنبض الحياة', 'فجأة انقلبت الحياة رأساً على عقب وأصبحت تحت الأرض لا فوقها', 'ما بين الحياة والموت', '1776216763_نجاة١.jpeg'),
(27, 'خرج من الركام....لكنه حمله في قلبه', 'يحمل بين يديه أغلى ما يملك فلذة كبده وروحه', 'ما بين الحياة والموت', '1776216893_نجاة٢.jpeg'),
(28, 'بين الأنقاض....قصة حياة لم تنتهي', ' قدره أن يبقى حياً ولو اجتمعت عليه كل شظايا الموت ', 'ما بين الحياة والموت', '1776217056_نجاة٣.jpeg'),
(29, 'بين الأنقاض .... انتهت حكايات لم تكتمل', 'طفلٌ بريء كان يلعب انتهت حياته بين الحجارة والركام', 'ما بين الحياة والموت', '1776217238_نجاة٤.jpeg'),
(30, 'في العتمة.....انطفأت أرواح بصمت ', ' بين الركام انطفأت الروح وبقي الجسد شاهداً على جريمة بشعة', 'ما بين الحياة والموت', '1776217387_نجاة٥.jpeg'),
(31, 'بين الغبار....ضاعت أنفاسٌ أخيرة', 'كان هناك أملٌ في انقاذه لكنه رحل إلى السماء', 'ما بين الحياة والموت', '1776217534_نجاة٦.jpeg'),
(32, 'من قلب الدمار....يولد الصمود', 'رغم الوجع بقي صامداً لينقذ أرواح ما زالت تصارع بين الحياة والموت', 'ما بين الحياة والموت', '1776217691_نجاة٧.jpeg'),
(33, 'النجاة معجزة....تكتب وسط الدمار', 'حوّم الموت حوله لكن القدر كتب له النجاة مجدداً', 'ما بين الحياة والموت', '1776217905_نجاة٨.jpeg'),
(34, 'خرج حياً...وكأن الحياة اختارته من جديد', 'بوجه مشوه مليء بالجروح والندبات اختارته الحياة ليكمل فيها ', 'ما بين الحياة والموت', '1776218002_نجاة ٩.jpeg'),
(35, 'تحت الركام ....ناموا دون أن يودعوا أحد ', 'ذهب إلى السماء دون أن يودع أحبابه على الأرض', 'ما بين الحياة والموت', '1776218167_نجاة١٠.jpeg'),
(36, 'القيد في اليد.....لكن الروح حرة', 'حملة اعتقالات واسعة شنها الاحتلال الاسرائيلي ضد الشبان خلال اقتحام مدينة غزة ', 'قيود الحرية', '1776588675_أسرى١.jpeg'),
(37, 'الاعتقال وجع صامت....لا يسمعه الجميع', 'تقييد واعتقال شبان من مدينة غزة خلال الاقتحام الاسرائيلي دون أي سبب', 'قيود الحرية', '1776588804_أسرى٢.jpeg'),
(38, 'الاعتقال ليس قيداً للجسد.....بل امتحان للروح', 'إهانة وذل  يتعرض لها الأسرى المعتقلين من قطاع غزة عدا التعذيب بأبشع صوره دون أن يدافع عنهم أحد ', 'قيود الحرية', '1776589040_أسرى٣.jpeg'),
(39, 'الحرية تُسلب.....لكن الإرادة لا تُقيد', 'يحاولون كسر الإرادة لشعب تمشي الإرادة في دمه وروحه ولا يمكن لشيء كسره..... ', 'قيود الحرية', '1776589248_أسرى٤.jpeg'),
(40, 'في الزنازين...يولد الصمود من الألم', 'على الرغم من الألم والإهانة ما زال الأسرى صامدين في وجه المحتل', 'قيود الحرية', '1776589359_أسرى٥.jpeg'),
(41, 'بين القضبان....قصص لا تنسى', 'قصص لا يمكن نسيانها كانت بين القضبان ما زالت في ذاكرة كل من عاشها....', 'قيود الحرية', '1776590110_أسرى٦.jpeg'),
(42, 'الاعتقال زمن ثقيل.....يمر ببطء مؤلم', 'كل واحدٍ منهم ينتظر لياتي دوره في التعذيب الوقت يمر ببطء لا يمكن توقعه...', 'قيود الحرية', '1776590293_أسرى ٧.jpeg'),
(43, 'الحرية حلم....لا يغيب عن الأسير ', 'رغم كل ما مر به الأسير بقيت الحرية الحلم الذي ينتظره ليلتقي مع بقي قلبه معهم في الخارج...', 'قيود الحرية', '1776590390_أسرى٨.jpeg'),
(44, 'الحرية صوت لا يمكن إسكاته', 'بعد الحرية لا يمكن لأي شيء إسكات الحق والدفاع عنه....', 'قيود الحرية', '1776590536_أسرى٩.jpeg'),
(45, 'الخيمة ليست بيتاً....لكنها تحاول أن تكون وطناً', 'في غمضة عين ذهب البيت وحلت مكانه خيمة من القماش لتكون طناً لأهلها تحميهم من برد الشتاء وحر الصيف', 'رحلة النزوح', '1776590696_نزوح٥.jpeg'),
(46, 'الحياة قاسية......لكنها تُنبت فينا القوة', 'تحولت حياتهم من مقاعد الدراسة إلى الجلوس أمام النار لصنع مقومات الحياة ومحاولة الحصول على أدناها....', 'رحلة النزوح', '1776590900_نزوح٦.jpeg'),
(47, 'نضحك أحياناً.....لنخفي وجعاً كبيراً', 'لا يمكن لأي أحد اخفاء الضحكة البريئة من وجوه الأطفال البريئة لكن قلوبهم مليئة بالفقد والوجع....', 'رحلة النزوح', '1776591132_نزوح٧.jpeg'),
(48, 'خلف كل جائع.....قلب ينتظر الرحمة', 'في طوابير الجوع لا يُسأل عن العمر يقف الأطفال بقلوب أنهكها الجوع والفقد ليحصلوا على لقمة لا تكفي لسد رمقهم....', 'صرخات الجوع', '1776591304_مجاعة٣.jpeg'),
(49, 'نودّعهم بالدعاء....ونحملهم في الذاكرة للأبد ', 'عائلاتٌ كاملة اختارت الرحيل معاً لكنهم تركوا خلفهم أحباب يودعونهم بالدموع والدعاء بقلب مثقل بالحزن والفقد', 'سير الشهداء', '1776888484_شهداء٦.jpeg'),
(50, 'شهيد يحمل شهيد ', 'هكذا هي الحياة في غزة كلنا جنازات مؤجلة من حمل الشهيد على كتفه بالأمس حُمل هو اليوم على الأكتاف كشهيد ليتلقى مع من سبقه من أحبابه في جنات النعيم.', 'سير الشهداء', '1776888657_شهداء٧.jpeg'),
(51, 'كان ينقل الخبر حتى صار هو الخبر', 'في غزة يٌستهدف الصحفي لأنه أدى واجبه العملي في نقل رسالة المظلومين إلى العالم ووثق الحقيقة كاملة لكن كل ذلك لا يقلل من عزيمتهم ولا يضعفهم.', 'سير الشهداء', '1776889125_شهداء٨.jpeg'),
(52, 'في الغياب....حضروا أكثر', 'عندما يُقهر الرجال يكابرون على كل شيء لكنهم أمام غياب أحبابهم لا يبقى سوى الوجع والقهر.', 'سير الشهداء', '1776889639_شهداء٩.jpeg');

