INSERT INTO `Stories` (`id`, `title`, `categoryName`, `description`, `story_type`) VALUES
(12, 'بترٌ متجدد في جسد الصحافة النازف', 'سير الشهداء', 'استهداف الصحفيين في غزة محاولة لإسكات صوت الحقيقة في ظل الأوضاع الحالية التي تشهدها غزة، فالصحفيون ليسوا مجرد ناقلين للأخبار، بل هم في قلب النضال من أجل الحقيقة، حيث إن استهداف الصحفيين في غزة يعتبر محاولة لوقف تدفق المعلومات وكبح جماح الحقيقة، أسفرت هجمات الاحتلال الإسرائيلي على استشهاد ما يزيد عن مئتين وستين شهيد صحفي، في انتهاك صارخ لكل القوانين والمواثيق الدولية التي تكفل حماية الإعلاميين أثناء النزاعات. ورغم المخاطر الجسيمة التي تحيط بهم، يواصل الصحفيون أداء رسالتهم الإنسانية والمهنية بكل شجاعة، حاملين الكاميرا والقلم كسلاح يوثق الألم وينقل المعاناة إلى العالم. إن استهدافهم لا يقتصر على إخماد صوت فردي، بل هو محاولة لطمس رواية شعب بأكمله، إلا أن الحقيقة تظل أقوى من محاولات إسكاتها، وتبقى شهادات الصحفيين حاضرة لتفضح الواقع وتنقل صورة لا يمكن إنكارها.\r\nوهنا نستعرض جزءًا بسيطًا من قصص صحفيين غادروا تاركين خلفهم أثرًا من الحزن لا يُمحى، وذاكرةً مثقلةً بالوجع، قصصًا تروي شجاعة الكلمة في وجه الخطر، وتبقى شاهدًا خالدًا على تضحياتهم في سبيل أن تصل الحقيقة إلى العالم.', 'multiple'),
(13, 'جهنم على الأرض ', 'قيود الحرية', 'شهادات مروعة لأسرى فلسطينيين تعرضوا لأبشع أنواع التعذيب في سجون الاحتلال الإسرائيلي بتقرير يحمل عنوان اهلاً بكم في جهنم ', 'multiple'),
(14, 'الجوع أقسى من القصف', 'صرخات الجوع', 'حكايات عن إنسان يصارع للبقاء، عن كرامة تُختبر كل يوم، عن صمودٍ يتشكل في أقسى الظروف...\r\nبين ركام البيوت وشحّ المساعدات في شمال قطاع غزة، تتفاقم المأساة في مدينة بيت حانون حيث تعيش آلاف العائلات تحت وطأة الجوع، ويواجه الأطفال تحديدا خطر الموت البطيء في ظل غياب الغذاء والدواء ووسائل الحياة الأساسية.', 'multiple'),
(15, 'طبيب قاوم الإبادة بعلاج الغزيين رغم الإصابة والاعتقال', 'قيود الحرية', 'حسام أبو صفية طبيب فلسطيني ومدير مستشفى كمال عدوان الواقع شمال قطاع غزة، اعتقلته قوات الجيش الإسرائيلي يوم 27 ديسمبر/كانون الأول 2024، وهو حاصل على درجة الماجستير وشهادة البورد الفلسطيني في طب الأطفال وحديثي الولادة', 'single'),
(16, 'ناشط وثق حرب الإبادة الإسرائيلية في غزة', 'سير الشهداء', 'ناشط ومصور وصحفي فلسطيني من غزة، ولد عام 1998 وقتل برصاص مسلحين في أكتوبر/تشرين الأول 2025. اشتهر بتوثيقه حرب الإبادة الجماعية الإسرائيلية على قطاع غزة بعدسته، حتى صار من أبرز الأصوات الميدانية التي جسّدت معاناة المدنيين ونقلتها إلى العالم.', 'single'),
(17, 'ساعة بين الفقد واللقاء', 'قيود الحرية', 'ناجي الجعفراوي هو أسير فلسطيني محرر، إمام وخطيب مسجد الشيخ زايد في قطاع غزة، ومدير العلاقات العامة في دار القرآن الكريم والسنة، اعتُقل من قبل قوات الاحتلال الإسرائيلي لأكثر من عام خلال الحرب، وأُفرج عنه في أكتوبر 2025، ليتفاجأ باستشهاد شقيقه الصحفي \"صالح الجعفراوي\" قبل يوم واحد من إطلاق سراحه.', 'single'),
(18, 'حكاية طفلة اسمها هند رجب', 'سير الشهداء', 'وجه جميل يشع بالبراءة وسمرة طبعتها شمس غزة بكثير من النور كأنها كوكب دري، الطفلة الفلسطينية هند رجب التي قتلت بدم بارد مع عائلتها وعدد من المسعفين على يد جيش الاحتلال، بعد أن كانت الناجية الوحيدة من نيران الدبابات الإسرائيلية في سيارة هربت فيها مع 6 من أقاربها في يناير/كانون الثاني 2024 خلال محاولتهم النزوح إلى مكان آمن بمدينة غزة، وتمت محاصرتهم بعدد من الدبابات التي استهدفتهم بصورة مباشرة.', 'single'),
(19, 'قتلوا براءة يوسف', 'سير الشهداء', 'حكايا يملؤها الوجع بكافة تفاصيلها بينما يعالج الطبيب مرضاه لا يستطيع أن ينقذ طفله، وهنالك الأم تبحث بين المصابين عن طفلها الصغير المدلل متمسكة بطرف خيط من الأمل لا يمكن رؤيته حتى أن تجده بين الجثامين تحول الوجه الأبيض ذو الملامح الطفولية البريئة إلى وجه لا يمكن معرفته بسبب ما أهلكته الشظايا والحروق............. ', 'single'),
(20, 'ما تبقى لأم من رضيعيها', 'سير الشهداء', 'بعد 11 عاما من الزواج والأمل والمعاناة والدعاء، أنجبت الفلسطينية رانيا أبو عنزة (35 عاما) توأمين، وظلت تحلم بتزيين رضيعيها بملابس جديدة في أول عيد لهما،لكن في منتصف إحدى ليالي مارس/آذار لعام 2024 ، قضت غارة جوية إسرائيلية على حلمها، إذ قتلت رضيعيها نعيم ووسام (5 أشهر) ووالدهما وسام، لتخسر أسرتها كامل وتبقى وحيدة مع ألم الفقد.....', 'single'),
(21, 'اعدام بدمٍ بارد', 'سير الشهداء', 'سيدة فلسطينية تعرضت لإطلاق نار مباشر من قناص إسرائيلي، وكان معها طفل يحمل الراية البيضاء أثناء النزوح من مدينة غزة في 12 نوفمبر/تشرين الثاني الماضي، قصة جديدة تثبت أن هذه الإبادة استهدفت الجميع على حد سواء ففي هذه القصة سيدة وبيدها طفل وبيدها الأخرى راية بيضاء لكنها كانت مستهدفة فما هو ذنبها ؟!', 'single'),
(22, 'على مقعد الدراسة انتهت الحياة ', 'سير الشهداء', 'كانت ملامح السعادة تعلو وجه الطفلة التي تنضم للدراسة لأول مرة منذ اندلاع الحرب على غزة في 7 أكتوبر/تشرين الأول 2023 ، لكنْ في لحظة واحدة، قرر جندي إسرائيلي يتمركز داخل الخط الأصفر شمالي القطاع، إنهاء حياة ريتاج قبل أن تعود إلى خيمة أسرتها.', 'single'),
(23, 'متحدون في الدم وفي الرحيل', 'سير الشهداء', 'قصة جديدة وحزن أكبر من أن يُحتمل يقف الوالدان أمام جثامين جميع أبناءهم رحلوا دفعةً واحدة تاركين خلفهم ألم في قلوب أحبابهم.....', 'single'),
(24, 'نزوح وحصار وموتى لا يُدفنون', 'رحلة النزوح', 'لم يتوقف الوجع على النزوح والحصار فقط على نغم بل شاهدت موت أحبابها وتركهم دون دفن إلى مثواهم الأخير', 'single'),
(25, 'رحلة عبر الجحيم', 'رحلة النزوح', 'قصة عائلة فلسطينة جسدت معنى الصمود في رحلة نزوحها من شمال قطاع غزة إلى جنوبه', 'single'),
(26, 'من الألم إلى الحرية', 'قيود الحرية', 'قصة تسنيم ليست حكاية نجاة فقط؛ إنها سؤال أخلاقي وسياسي وإنساني، فكيف تُخطف ممرضة تعالج الجرحى؟ ولماذا يُستخدم الجسد البشري كورقة مساومة؟ وهل سيحاسب المجرمون الذين باعوا دينهم ووطنهم وشرفهم وارتضوا أن يعيشوا بساطير لأقذر جيش عرفه التاريخ؟ ', 'single');

