--
-- Table structure for table `Story`
--

CREATE TABLE `Story` (
  `id` int(11) NOT NULL,
  `story_id` int(11) DEFAULT NULL,
  `heroName` varchar(100) DEFAULT NULL,
  `details` text DEFAULT NULL,
  `image` varchar(255) DEFAULT NULL,
  `title` varchar(255) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Dumping data for table `Story`
--

INSERT INTO `Story` (`id`, `story_id`, `heroName`, `details`, `image`, `title`) VALUES
(1, 12, 'أنس الشريف', 'من هو أنس الشريف ؟\r\n وُلد الصحفي أنس جمال محمود الشريف في الثالث من ديسمبر/كانون الأول 1996، ونشأ في مخيم جباليا شمال شرقي قطاع غزة. تزوج من السيدة بيان السنوار، ولديه طفلة تُدعى شام ابنته الكبرى (5 أعوام) وقد كان لها النصيب الأوفر من الحب والدلال حتى إنه جعلها مبتدأ الوصية التي كتبها قبيل استشهاده، أما طفله الثاني صلاح فهو وليدُ الحرب وعمره عام ونصف العام، بدأ مؤخرا بالتعرف على وجه أبيه والتعلق به، وبدأ لفظ \"بابا\" يتدحرج على شفتيه حتى انتزعه الموت من حجره ليغدو وحيدا قبل أن يتنعم بدلاله, تلقى الشريف تعليمه في مدارس وكالة غوث وتشغيل اللاجئين الفلسطينيين \"الأونروا\" وكذلك المؤسسات التعليمية لوزارة التربية والتعليم والفلسطينية. التحق بقسم الصحافة والإعلام في جامعة الأقصى عام 2014 ودرس تخصص الإذاعة والتلفزيون , بدأ الشهيد الصحفي أنس عمله متطوعا في شبكة الشمال الإعلامية، وكان يُعد تقارير عن الأوضاع في قطاع غزة لصالح شبكات عديدة, انتقل للعمل مراسلا لدى شبكة الجزيرة بعد بدء العدوان الإسرائيلي على قطاع غزة عقب عملية \"طوفان الأقصى\" التي شنتها المقاومة الفلسطينية في 7 أكتوبر/تشرين الأول 2023 على مستوطنات غلاف غزة, عمل يوميا على إعداد تقارير عن المجازر التي ارتكبها جيش الاحتلال الإسرائيلي والأوضاع الاجتماعية في القطاع، وتعرض للتهديد من قوات الاحتلال بسبب تغطياته للعدوان, وفي نوفمبر/تشرين الثاني 2023، كشف الشريف عن تلقيه تهديدات ورسائل عبر تطبيق \"واتساب\" من ضباط إسرائيليين تهدف إلى إجباره على وقف تغطيته للحرب الإسرائيلية على القطاع، مؤكدا عدم مغادرته الميدان وبقاءه مستمرا في التغطية الإعلامية بشمال القطاع, ويوم 11 ديسمبر/كانون الأول من العام نفسه، قصفت طائرات الاحتلال الإسرائيلي منزل الصحفي الشريف، مما أدى إلى استشهاد والده، موضحا أنه اضطر إلى دفنه في ساحة مدرسة تابعة لوكالة \"الأونروا\"، وتعهد بالاستمرار في تغطية جرائم الاحتلال بحق الفلسطينيين في القطاع, ومع تواتر الأنباء عن قرب الإعلان عن وقف إطلاق النار في قطاع غزة منتصف يناير/كانون الثاني 2025، خلع الشريف خوذته قائلا أثناء البث المباشر إنها أثقلت كاهله، وإن بزته الصحفية أصبحت جزءا منه على مدى 15 شهراً. اغتياله: اغتال جيش الاحتلال الإسرائيلي في وقت متأخر من مساء يوم الأحد 10 أغسطس/آب 2025 الصحفي أنس الشريف و5 آخرين، بعدما استهدف خيمة للصحفيين قرب مستشفى الشفاء في مدينة غزة, وفي بيان نشره بعد الغارة، أقر جيش الاحتلال باستهداف أنس الشريف ووصفه بأنه \"إرهابي تنكر بزي صحفي في قناة الجزيرة\"، مدعيا أنه كان قائد خلية في حركة المقاومة الإسلامية (حماس) وروّج لإطلاق الصواريخ على إسرائيل.\r\n الوداع الأخير لعائلته : \r\nتسلل أنس في قلب الليل بلا موعد مسبق حيث رُكنه الآمن في آخر جمعة وآخر اجتماع، زيارة مفاجئة بعد غياب لأكثر من شهر، باغت فيها زوجته التي وجدته أمامها بذراعيه المُشرعتين كأنهما العالم بأسره، حسب تعبيرها, على غير العادة هرول إلى طفليه وأصر على إيقاظهما، ثم حمل كل واحد منهما بين يديه، يقذفه في الهواء ثم يتلقّفه ويحتضنه بقوة، يدور بهما مرارا كأنما يُخزّن من ضحكاتهما ما يكفيه للغياب القادم, تنقّل أنس بين الأرائك وتمدد على الأرض، ثم استلقى على السرير فاتحا ذراعيه، كان جسده مرهقا، لكن لأول مرة يُفصح عن ذلك، \"تحدثنا طويلا، كانت ملامحه تشي بإنهاك لم أره منه قط، لأول مرة يعبّر عن شوقه لراحة ولعيشة بسيطة خالية من القلق والتهديد\"، تقول زوجته بيان, لأول مرة أنس بلا هواتف ولا مقاطعات ولا أخبار عاجلة، لا يحمل شيئا سوى مشاعره التي يحوم بها في أرجاء البيت كفراشة تنثر دفئها بين الغرف، وفي عينيه سكون عميق، وفي حضنه وداع مكنون، وبينما هو كذلك علا صوت داخل بيان \"هل هو اللقاء الأخير؟\" لكنها خنقته، وأقنعت نفسها بأنه الشوق، لا الوداع, بعد ساعات همّ أنس بالمغادرة، كل خطوة كان يبتعد فيها عنها كانت تشعر كأن سكينا ينغرس في قلبها، وحين بلغ الباب، التفت إليها وقال مبتسما \"موعدنا يوم ميلادك، راجع وفي يدي هدية لك\"، ضحكت بيان على استحياء فهي تعلم أنه كان يصنع من مناسباتها طقسا مقدسا، وشيعته بنظراتها حتى اختفى, مر يومان على هذا اللقاء حتى جاء يوم ميلادها في 14 أغسطس/آب الجاري على هيئة يوم عزاء، لم يأتِ فيه أنس بهديته، بل عاد محمولا على الأكتاف بلا صوت ولا هدية ولا مفاجأة ولا عناق, دقيقةٌ واحدة فقط هي المهلة التي مُنحت لبيان كي تودع حبيبها وداعا أخيرا، صاحت فيهم \"افتحوا الكفن أريد أن أرى وجهه وأقبل وجنتيه\"، لكن من حولها رفضوا، فأنس \"بلا عينين\"، تجهش بالبكاء وهي تتحسسه من فوق الكفن، \"جسده بارد، لحمه طري\", دقيقةٌ واحدة لم تتمكن فيها إلا من أن تهمس في أذنه سؤالا واحدا \"أين وعدك لي بأن نموت معا كي لا يتحسر أحدنا على الآخر؟ لم نتفق على هذا يا حبيبي، ألم تعدني بالرجوع يوم ميلادي؟!\"، همست بيان بعتبها، ثم رفعوه من أمامها وحملوه لمثواه الأخير.\r\n وصيته:\r\nهذه وصيّتي، ورسالتي الأخيرة.\r\nإن وصلَتكم كلماتي هذه، فاعلموا أن إسرائيل قد نجحت في قتلي وإسكات صوتي.\r\nبداية السلام عليكم ورحمة الله وبركاته \r\nيعلم الله أنني بذلت كل ما أملك من جهدٍ وقوة، لأكون سندًا وصوتًا لأبناء شعبي، مذ فتحت عيني على الحياة في أزقّة وحارات مخيّم جباليا للاجئين، وكان أملي أن يمدّ الله في عمري حتى أعود مع أهلي وأحبّتي إلى بلدتنا الأصلية عسقلان المحتلة \"المجدل\" لكن مشيئة الله كانت أسبق، وحكمه نافذ.\r\nعشتُ الألم بكل تفاصيله، وذُقت الوجع والفقد مرارًا، ورغم ذلك لم أتوانَ يومًا عن نقل الحقيقة كما هي، بلا تزوير أو تحريف، عسى أن يكون الله شاهدًا على من سكتوا ومن قبلوا بقتلنا، ومن حاصروا أنفاسنا ولم تُحرّك أشلاء أطفالنا ونسائنا في قلوبهم ساكنًا ولم يُوقِفوا المذبحة التي يتعرّض لها شعبنا منذ أكثر من عام ونصف.\r\nأوصيكم بفلسطين، درةَ تاجِ المسلمين، ونبضَ قلبِ كلِّ حرٍّ في هذا العالم.\r\nأوصيكم بأهلها، وبأطفالها المظلومين الصغار، الذين لم يُمهلهم العُمرُ ليحلموا ويعيشوا في أمانٍ وسلام،\r\nفقد سُحِقَت أجسادهم الطاهرة بآلاف الأطنان من القنابل والصواريخ الإسرائيلية، فتمزّقت، وتبعثرت أشلاؤهم على الجدران.\r\nأوصيكم ألّا تُسكتكم القيود، ولا تُقعِدكم الحدود، وكونوا جسورًا نحو تحرير البلاد والعباد، حتى تشرق شمسُ الكرامة والحرية على بلادنا السليبة.\r\nأُوصيكم بأهلي خيرًا،\r\nأوصيكم بقُرّة عيني، ابنتي الحبيبة شام، التي لم تسعفني الأيّام لأراها تكبر كما كنتُ أحلم.\r\nوأوصيكم بابني الغالي صلاح، الذي تمنيت أن أكون له عونًا ورفيق دربٍ حتى يشتدّ عوده، فيحمل عني الهمّ، ويُكمل الرسالة.\r\nأوصيكم بوالدتي الحبيبة، التي ببركة دعائها وصلتُ لما وصلت إليه، وكانت دعواتها حصني، ونورها طريقي. \r\nأدعو الله أن يُربط على قلبها، ويجزيها عنّي خير الجزاء.\r\nوأوصيكم كذلك برفيقة العمر، زوجتي الحبيبة أم صلاح بيان، التي فرّقتنا الحرب لأيامٍ وشهورٍ طويلة، لكنها بقيت على العهد، ثابتة كجذع زيتونة لا ينحني، صابرة محتسبة، حملت الأمانة في غيابي بكلّ قوّة وإيمان.\r\nأوصيكم أن تلتفوا حولهم، وأن تكونوا لهم سندًا بعد الله عز وجل.\r\nإن متُّ، فإنني أموت ثابتًا على المبدأ، وأُشهد الله أني راضٍ بقضائه، مؤمنٌ بلقائه، ومتيقّن أن ما عند الله خيرٌ وأبقى.\r\nاللهم تقبّلني في الشهداء، واغفر لي ما تقدّم من ذنبي وما تأخّر، واجعل دمي نورًا يُضيء درب الحرية لشعبي وأهلي.\r\nسامحوني إن قصّرت، وادعوا لي بالرحمة، فإني مضيتُ على العهد، ولم أُغيّر ولم أُبدّل.\r\nلا تنسوا غزة…. \r\nولا تنسوني من صالح دعائكم بالمغفرة والقبول.\r\nأنس جمال الشريف.. \r\n06.04.2025.', '1775854312_ِانس الشريف.jpg', 'صوت غزة الذي اغتاله جيش الاحتلال الإسرائيلي'),
(2, 12, 'إسماعيل الغول', 'من هو إسماعيل الغول ؟\r\nفي مخيم الشاطئ هناك في غرب مدينة غزة، حيث هجر أجداده من قرية هربيا سنة 1948، ولد إسماعيل الغول عام 1997 في عيادة الرمال التابعة لوكالة الغوث. وفي أجواء المخيم حفظ أحاديث الأجداد عن البلاد وحلم العودة، وبين أزقته عايش ظروفه الصعبة، وشهد أكثر من خمسة حروب وتصعيدات مختلفة. كان إسماعيل متزوجًا وله طفلة صغيرة ظلّ ينشر عنها منشورات بين الفينة والأخرى على حساباته الرسميّة في مواقع التواصل الاجتماعي وكيف أنها تعيشُ سنينها الأولى بعيدًا عنه وتكبر دون أن تُتاح له الفرصة لرؤيتها.[12] لم يُشاهد إسماعيل – بسببِ الاستهدافات الإسرائيليّة المتكررة والمتعمّدة لكل من يتحرّك بين المحافظات – ابنته منذ بداية الحرب فهي ووالدتها في المحافظة الوسطى بينما ظلَّ هو في محافظة الشمال مرتبطًا بعمله ومستمرًا في تغطية ما يحدث من أحداث متواليّة ومتسارعة.\r\nتعليمه وعمله:\r\n درس المراحل الابتدائية والإعدادية والثانوية في غزة، ثم التحق بالجامعة الإسلامية، وتخرج فيها بدرجة البكالوريوس في الصحافة والإعلام.\r\nبعد تخرجه عمل مراسلا لصحيفتي \"فلسطين\" و\"الرسالة\" الفلسطينيتين، وكان نشيطا في وسائل التواصل الاجتماعي ينقل عبرها مأساة شعبه في قطاع غزة ،بعد اشتداد حرب الإبادة، اضطُر العديد من الصحفيين ممن فقدوا بيوتهم، أو أمرهم الجيش بإخلاء مناطق سكناهم، إلى التوجه لمستشفى الشفاء طلبا للإيواء، لكن العديد منهم اضطروا إلى النزوح من شمال قطاع غزة إلى جنوبه خوفا من أن يصل إليهم جيش الاحتلال؛ الذي يستهدف الصحفيين حتى ولو كانوا يرتدون ما يشير إلى هويتهم الصحفية. أما إسماعيل فقد قرر البقاء في قلب المدينة رغم كل التهديدات والمخاطر. وعن بداية عمل إسماعيل مع قناة الجزيرة، يقول أخوه جهاد إنهم فوجئوا جميعا بظهوره على الشاشة؛ فالأوضاع الميدانية لمدينة غزة كانت صعبة جدا يجري فيها استهداف كل شيء، عدا عن انقطاع شبكة الاتصالات والإنترنت في تلك الفترة.  في نوفمبر/ تشرين الأول لعام 2023 ظهر إسماعيل أولا عبر مداخلاته الهاتفية من حين إلى آخر، ثم ظهرت تغطياته المباشرة، وتقاريره التلفزيونية التي بثتها أيضا وسائل إعلامية غربية كبرى؛ ليحدثنا عن صورة الوضع المأساوية من قلب الحدث\r\nاعتقاله:\r\nاعتقله الجيش الإسرائيلي في مستشفى الشفاء بغزة منتصف مارس/آذار 2024 بعد أن اقتحمت قوات الاحتلال المستشفى بدعوى أن المقاومة تتخذه مقرا عسكريا، وتم احتجاز إسماعيل 12 ساعة، وفور الإفراج عنه استمر في تغطيته من أمام مستشفى الشفاء وروى ما جرى له أثناء الاعتقال، كما استمر في نقل معاناة أهالي غزة، وقال الزميل إسماعيل الغول آنذاك للجزيرة إنه اضطر، وغيره من الصحفيين، إلى تسليم أنفسهم لقوات الاحتلال التي أجبرتهم على خلع ملابسهم بشكل كامل، بعد أن جرفت خيمة الصحفيين ودمرت سياراتهم خلال اقتحام مجمع الشفاء قبل أن يفرج عنه، ويظل زملاؤه الصحفيون مجهولي المصير إلى هذه اللحظة.\r\nاغتياله:\r\nوفي مساء الأربعاء 31 يوليو/تموز 2024 اغتالت قوات الاحتلال إسماعيل الغول وزميله المصور رامي الريفي في مخيم الشاطئ بمدينة غزة، وقال مراسل الجزيرة الشهيد الصحفي  في مدينة غزة أنس الشريف إن مسيّرات إسرائيلية استهدفت الزميلين إسماعيل ورامي بشكل مباشر، مما أدى إلى استشهادهما على الفور وأشار إنّه لا يستطيعُ رفع القماش عن الجثة بعد كل التشويه الذي طالها من جرّاء القصف الإسرائيلي المتعمَّد بل إنّ رأس إسماعيل قد انفصلَ بالكامل عن جسده.', '1776009880_إسماعيل_الغول.jpg', 'صحفي صنعته الحرب واغتالته إسرائيل'),
(3, 13, 'تامر قرموط', 'حتى اندلاع الحرب كنت أسكن مع زوجتي منار علي صالح (36 عامًا) وأولادنا الخمسة، عامر (17 عامًا) وعبد الرؤوف (16 عامًا) وهبة اللّه (13 عامًا) ومحمد (10 أعوام) وحلا (3 أعوام)، في منزل في بيت لاهيا. في العام 2001 أصبت في ساقي، ومنذ ذلك الحين أعاني من عجز جسماني.\r\nكنا نسكن في شقة صغيرة في مبنى العائلة، إلى الغرب من مستشفى كمال عدوان، كانت حياتنا بسيطة، لكنها كانت مستقرة نسبياً، على الرغم من الصعوبات المالية.\r\nفي صباح يوم 7 تشرين الأول 2023، في الساعة 6:30، استيقظت على أصوات انفجارات قوية. بعد لحظات، عاد أطفالي، الذين كانوا قد غادروا إلى المدرسة، إلى المنزل. بدأت بمتابعة الأخبار على التلفزيون وعلى شبكات التواصل الاجتماعي وعلمت أن المقاومة الفلسطينية أطلقت صواريخ وأنه قد تم اختراق السياج الحدودي. أدركت أن الرد سيكون شديداً وقررت البقاء في المنزل مع زوجتي وأطفالي، في مساء يوم الثلاثاء، 10.10.23، قصفت طائرات حربية إسرائيلية منزل عائلة عفانة الذي كان قريباً من منزلنا. سقطت شظايا من المبنى على منزلنا وحطمت زجاج نوافذه، لكننا لم نُصّب.\r\nفي 13.10.23، وزع الجيش الإسرائيلي منشورات تأمرنا بمغادرة منزلنا والتوجه جنوباً، إلى ما وراء وادي غزة. لم نوافق على المغادرة وكان هناك أقارب ومعارف لنا بقوا معنا أيضاً - ما يقارب 70 شخصاً، معظمهم من النساء والأطفال، في 23.11.23، سقطت قذيفة مدفعية على شقة أخي رائد في الطابق الرابع من المبنى. تسبب ذلك بأضرار جسيمة للمبنى، لكن لم تقع إصابات. أرعبنا هذا الحادث كثيراً فقررنا الانتقال إلى مستشفى كمال عدوان، وصلنا إلى المستشفى في ليلة 24.11.23. في ذلك اليوم، أعلن عن اتفاق لوقف إطلاق نار بين الفصائل الفلسطينية وإسرائيل. استمر وقف إطلاق النار 7 أيام عدنا إلى منزلنا طوال تلك الفترة.\r\nعندما استؤنفت عمليات القصف واستمرت العمليات البرية الإسرائيلية، انتقلنا إلى مستشفى كمال عدوان مرة أخرى. تمكنت من إيجاد مكان لزوجتي والأولاد للمبيت في قسم الأطفال، ونمت أنا على درجات المبنى، بسبب الازدحام الشديد هناك. كانت الظروف هناك صعبة: المياه لم تكن صالحة للشرب وكان الطعام قليلًا وكان من الصعب العثور على حفاضات وحليب لطفلتي الرضيعة. تسببت الغارات المتكررة التي شنتها الطائرات الحربية باشتعال حرائق ونشر الرعب، ثم المعاناة المستمرة.\r\nفي 12.12.23، في الساعة 9:00، طوّقت الدبابات الإسرائيلية مستشفى كمال عدوان، حلقت طائرات مقاتلة وطائرات استطلاع وطائرات بدون طيار فوق المستشفى، وكان هناك إطلاق نار كثيف. أصابت إحدى الرصاصات صدر أحد الأشخاص الذين كانوا في المستشفى، دعا الجيش الرجال الذين تتراوح أعمارهم بين 15 و55 عامًا إلى الخروج إلى فناء المستشفى. خرجت مع ابني عامر، ويداي مرفوعتان. ما رأيناه في الخارج كان مخيفًا للغاية. كانت هناك مركبات عسكرية منتشرة في فناء المستشفى والشوارع المجاورة، عشرات الجنود منتشرين على الأرض وقناصة على أسطح المباني العالية المحيطة بالمستشفى. كان هناك حوالي 300 رجل في الفناء. أمرونا بخلع جميع ملابسنا، باستثناء الملابس الداخلية. جلسنا على الأرض لمدة ساعة تقريبًا، ثم نقلونا إلى قطعة أرض خلف محطة وقود البراوي. هناك، أجروا مسحًا لعينيّ وأعطوني بنطالا وقميصًا، ثم عصبوا عينيّ وقيدوا يديّ بالأصفاد، نقلوني إلى مبنى مجاور وبدأوا التحقيق معي: طلبوا مني تقديم بياناتي الشخصية واتهمني المحقق بالانتماء إلى حركة حماس. أنكرت التهمة فهددني المحقق بأنه إذا لم أعترف، فسوف يُحضر زوجتي ويأمر الجنود الآخرين باغتصابها كما اتهمني بالانتماء إلى حركة الجهاد الإسلامي، وأنكرت هذه التهمة أيضًا خلال التحقيق، شتمني المحقق ووصفني ب\"ابن العاهرة\" و\"ابن الزانية\" وغيرها من الكلمات الجارحة.\r\nبعد ذلك، هاجمني أربعة جنود بوحشية، ضربوني وركلوني، وضربوني بأعقاب بنادقهم، أصابت إحدى الضربات مؤخرة رأسي، فقدت توازني وسقطت فاقدًا الوعي، عندما استعدت وعيي جزئياً، أدركت أن الجنود يحملونني ويلقون بي في شاحنة تقلّ معتقلين آخرين لم نكن نعرف إلى أين تأخذنا الشاحنة كان السائق يقود بسرعة كبيرة وقد توقف فجأة عدة مرات أثناء الرحلة، مما تسبب بارتطامنا ببعضنا البعض، مراراً وتكراراً. في النهاية توقفت الشاحنة. أنزلوني منها وفورًا هاجمني كلب، انقض عليّ وبدأ يضريني بعنف شديد، على الرغم من أنه كانت هنالك كمامة على فمه في ذلك الوقت، كان الجنود يضربوننا ويشتموننا وأمهاتنا.\r\nركز الجنود ضرباتهم على رأسي: تلقيت ثماني لكمات متتالية على رأسي، مما تسبب لي بنزيف في أذني اليسري منذ ذلك الحين، تأثرت قدرتي على السمع في هذه الأذن ومن جراء ذلك، ما زلت أعاني من طنين في الأذنين حتى اليوم، أجبرني الجنود على خلع ملابسي بالكامل والاستلقاء على بطني. تركوني في هذا الوضع لمدة ساعتين تقريبًا، في البرد القارس وتحت المطر الغزير. طوال ذلك الوقت، كان الجنود يضربونني ضربًا مبرحًا وقد استمر ذلك لفترة طويلة. عندما توقفوا عن الضرب، لاحظت أنه لا يوجد معتقلون آخرون حولي وأنني بقيت وحدي في الفناء.\r\nأثناء التعذيب، قام أحد الجنود باغتصابي دفع عصا خشبية بقوة في فمي وشرجي وتركها هناك لمدة قريبة من الدقيقة، ثم سحبها بعد ذلك، أدخل الجندي العصا مرة ثانية وبقوة أكبر، فصرخت بصوت عالٍ بعد دقيقة، سحب العصا مرة ثانية وأمرني أن أفتح فمي ثم أدخل العصا في فمي وأجبرني على لعقها غمرتني مشاعر الظلم والإهانة، ومن شدة الإذلال فقدت الوعي لبضع دقائق.\r\nفي مرحلة ما، جاءت ضابطة وأمرت الجنود بالتوقف عن التنكيل بي نزعت الأصفاد البلاستيكية عن يديّ واهتمت بأن يُحضروا لي \"أفرول\" أبيض اللون ارتديت الأفرول ثم قالت لي \"انتظر، انتظر\"، وأحضرت لي كوبًا من الماء قلت للضابطة أنني بحاجة إلى الذهاب إلى الحمام، لأنني أشعر بأن الدم ينزف من فتحة الشرج أعطتني ورق تواليت عندما وصلت إلى الحمام، نزع الجنود العصابة عن عيني اكتشفت أن الدم كان ينزف بالفعل. بعد أن انتهيت من التنظيف وتوقف النزيف، ارتديت الأفرول مرة أخرى بعد أن خرجت من الحمام، غطوا عينيّ مرة أخرى وقيدوا يديّ إلى الخلف بأصفاد بلاستيكية.بعد ذلك، نقلوني إلى غرفة كان فيها عدد منٍ المعتقلين وتركوني هناك لمدة ثماني ساعات تقريباً.\r\nخلال الساعات التي قضيناها هناك، اعتدى الجنود علينا بالتناوب، ضربًا وإذلالًا بعد ذلك، نقلونا بالحافلة إلى مكان لم نعرف اسمه خلال النقل، ضربوني مرة أخرى، ركلوني وضربوني بأعقاب البنادق استمرت الرحلة قرابة الساعتين وعندما توقفت الحافلة، أنزلونا منها، مع الضرب مرة أخرى جمّعونا جميعًا في الفناء ثم نزع الجنود الأصفاد والأغطية عن أعيننا وأعطونا سراويل وقمصانًا رمادية ارتديتها دون ملابس داخلية. هناك، حصلت أيضًا على رقم السجين الخاص بي - 0525422.\r\nأخذوني لإجراء فحص طبي. وزنوني فكان وزني 108 كيلوغرامات سألني الطبيب إذا كنت أعاني من أمراض مزمنة أجبت بالنفي، لكنني أخبرته أنني أعاني من إعاقة في ساقي وأنها تؤلمني الآن أكثر بسبب الضرب المبرح الذي تعرضت له أعطاني الطبيب مسكتا للألم عندما بدأت أخبره أنهم اغتصبوني بعصا، قاطعني الطبيب وأمر الجنود بإخراجي من غرفة الفحص.\r\nأدخلوني إلى بركس كبير كان فيه حوالي مائة معتقل كان الجو باردًا جدًا هناك، لأن البركس كان مفتوحًا من جميع الجوانب وسقفه كان مصنوعًا من ألواح الصفيح قيّد الجنود يديّ إلى الأمام وعصبوا عينيّ. في هذا المكان، أجبروني على الجلوس على الأرض. أعطونا القليل من الطعام، الذي لم يكن كافياً لإشباع جوعنا، وقليلاً من الماء بقيت في البركس من 13.12.23 حتى 22.12.23.\r\nفي ذلك اليوم، أخذوني إلى ما يسمى \"غرفة الديسكو\"، كانت أرضية الجناح مغطاة بحجارة حادة وفي الغرفة  مكبرات صوت تُصدر أصواتاً مزعجة بصوت مرتفع وبشكل متواصل، خلال اليوم نفسه، جرى التحقيق معي عدة مرات متتالية في الغرفة نفسها كان هناك محقق يرتدي ملابس مدنية، يجلس خلف مكتب عليه جهاز حاسوب، ركزت أسئلته على تفاصيل شخصية عنّي وأين كنت في 7 تشرين الأول، مواقع الأنفاق ومواقع الأسرى الإسرائيليين وبعض الأسئلة عن أفراد عائلتي في كل تحقيق، كان المحققون يكررون الأسئلة نفسها، وكنت أنا أكرر الإجابات نفسها.\r\n في 27.12.23 أعادوني إلى البركس لأننا كنا مقيّدين بأصفاد بلاستيكية ضيقة جداً طوال تلك الفترة، فقد تسببت هذه بتاكل أنسجة الجلد واللحم في مفصل يدي، كان النزيف مستمراً، وفي مرحلة ما انكشفت العظام في كلتا يدي كان الألم حادًا ومتواصلًا عندما تدهورت حالتي، نقلني الجنود إلى مكان توجد فيه طبيبة بدأت تعالجني قضت يومًا كاملًا في تصريف كميات كبيرة من الدم الملوث والجلطات الدموية من أصابع يدي، باستخدام معدات طبية بسيطة للغاية استمر العلاج ثلاثة أيام متتالية، وخلالها نقلوني عدة مرات من البركس إلى غرفة الطبيبة.\r\nخلال الفترة التي قضيتها في البركس، داهمت وحدات القمع المكان ثلاث مرات كانت مجموعات كبيرة من الجنود، مزودة بالأسلحة والكلاب، تقتحم المكان كان الجنود يأمروننا بالاستلقاء على الأرض ثم يسمحون للكلاب بالدوس على أجسادنا في إحدى تلك المداهمات، نطحني كلب بقوة في رأسي ألقى الجنود قنابل مسيلة للدموع وضربونا وشتمونا، في 1.1.24، قرأوا رقمي وأرقام حوالي 20 معتقلاً آخرين، ثم نقلونا إلى مكان يسمى \"الكلابة\" - وهي غرقة \"شَبْح\" فيها رافعة كانت تُستخدم في الماضي لتعليق السجناء في الغرفة، صوّرونا وأفردوا لي رقمًا جديدًا - 0987582، ثم صوروني مرة أخرى، وهذه المرة على خلفية علم إسرائيل الذي كان معلقًا على الحائط بعد ذلك، أدخلونا إلى غرفة صغيرة وعندما أخرجونا منها، مررنا عبر صف من الكلاب هاجمتني بوحشية بعد ذلك، قيدوا يديّ ورجلي بأصفاد معدنية ضيقة تسببت لي بألم شديد، ثم حمّلوني أنا والمعتقلين الأخرين على حافلة نقلتنا من \"سديه تيمان\" إلى سجن النقب (كتسيعوت) كانت الرحلة متواصلة واستمرت حوالي ثلاث ساعات.\r\nعندما دخلنا إلى المكان، هاجمنا الجنود وضربونا بوحشية، في طقسٍ يُسمى \"التشريفة\" (الاستقبال/ الترحيب) بعد ذلك، أعطوني ملابس جديدة، بنطالًا رمادي اللون وقميصًا أزرق، وأدخلوني إلى الزنزانة رقم 1 في الجناح رقم 6 كان في الزنزانة 15 سجينا و7 أسرّة فقط لذلك، كان ثمانية سجناء ينامون على فرشات على الأرض كان في الغرفة 10 فرشات، كنا نضعها جنباً إلى جنب، متلاصقة، حتى نتمكن من النوم عليها، احتجزوني في تلك الزنزانة 10 أيام فقط، ثم نقلوني إلى جناج الخيام، إلى خيمة بمساحة أمتار، كان فيها نحو 40 سجينا. كان في الخيمة 6 أسرة بطابقين. كنت جائعاً معظم الوقت، لأنهم كانوا يعطوننا القليل من الطعام وكان طعمه سيئًا أيضًا وأحيانًا، كان الخبز فاسدًا. أتذكر أنه بعد سبعة أشهر من الاعتقال، أحضروا لنا دلو شاي فيه صراصير، ونحن بالطبع لم نشرب منه، بعد فترة قصيرة من نقلي إلى الخيمة، بدأت أمراض جلدية بالانتشار بين السجناء: الجرب والقمل والدمامل. وقد أصبتُ بجميعها. كنت أعاني من حكة شديدة لم أتمكن من النوم بسببها وكنت أضطر أحيانًا إلى تمزيق الجلد بأظافري لتخفيف الألم، كما كنت أعصر البثور لإخراج القيح منها ظهرت البثور القيحية على الركبتين والمؤخرة بشكل رئيسي، عانينا من انتشار الجرب طوال عام وشهرين، وخلال تلك الفترة لم نحصل على مياه للاستحمام سوى مرتين فقط. كما زودونا بمرهم طبي كان يخفف الحكة تدريجياً استمرت الحكة لفترة طويلة، لكنها أصبحت أقل حدة مع مرور الوقت.\r\n كنت في الخيمة رقم 1، وسمعت عن شاب اسمه خليل هنية، من الخيمة رقم 4 في الجناح نفسه، توفي بعد إصابته بالجرب والدمامل. قالوا إنه فقد وعيه وسقط على رأسه وتوفي نتيجة لذلك، شاب آخر، يُدعى إبراهيم الزعانين، أطلق عليه لقب \"الجرب الأخضر\" بسبب خطورة حالته غطّى الجرب جسده بالكامل حتى انخفض وزنه إلى 40 كيلوغراماً.لاحقًا، نُقل إبراهيم إلى مكان آخر ولا أعرف حتى اليوم ماذا حل به، لكن انتشرت شائعة بين السجناء أنه توفي  شائعة أثارت ضجة كبيرة لأنه كان يعانى من تعذيب شديد القسوة.\r\nاحتجزوني في هذا الجناح لفترة طويلة. في بداية تموز 2025، نقلوني إلى جناح يسمى \"البح\"، وهو عبارة عن خيمة كبيرة (خيمة رقم 18) محاطة بالحديد من جميع الجهات وفي أحد جوانبها باب مزوّد بجهاز اتصال داخلي في البداية كنا نقضي حاجاتنا في دلو، كان الدكتور أحمد مهنا محتجزًا في هذا الجناح أيضًا، في قسم مجاور، وفي الخيمة رقم 18 وقعت حادثة مأساوية: توفي معتقل يُدعى أبو إسماعيل من خان يونس بسبب احتباس البول والبراز، مما تسبب له بانتفاخ شديد وتسمم داخلي نتيجة تمزق في الأمعاء بعد هذا الحادث، اضطروا إلى تركيب مراحيض للسجناء بدلاً من الدلو، وضمان تزويدنا بالمياه بشكل منتظم.\r\nفي يوم الجمعة الموافق 10.10.25، في الساعة 5:00 صباحاً، نقلوني مع سجناء آخرين إلى غرفة أخرى في الجناح رقم 1، وأعطونا ملابس جديدة. كنا 13 سجينًا. في اليوم التالي، 11.10.25، حوالي الساعة 20:00، زارنا ممثلان عن الصليب الأحمر ملأ استمارات، وسألاني إن كنت أفضل العودة إلى قطاع غزة أو السفر إلى الخارج، وأبلغوني أنني مدرج رسمياً في قائمة السجناء الذين سيتم الإفراج عنهم في إطار الصفقة.\r\nفي يوم الاثنين الموافق 13.10.25، حوالي الساعة 3:00 صباحاً، جاء جنود وقيدوا أيدينا وأرجلنا وأخذونا إلى فناء السجن هناك، أزالوا الأصفاد وأعطونا ملابس رياضية رمادية اللون عليها شعار مصلحة السجون في الساعة 4:00 صباحاً، أركبونا في حافلات، وتركونا جالسين فيها حوالي سبع ساعات حتى انطلقت سافرنا، وطوال الرحلة كان الجنود يهينوننا ويضربوننا، حتى وصلنا إلى معبر كرم أبو سالم [كيرم شالوم]. دخلنا إلى القطاع، حيث استقبلنا ممثلو الصليب الأحمر ونقلونا في حافلات أخرى إلى مستشفى ناصر في مدينة خان يونس.\r\nاستقبلتني عائلتي بفرح كبير، لكن سرعان ما وصلت الأخبار السيئة أخبروني أن اثنين من أصدقائي استشهدا: محمد قرموط (28 عامًا)، وهو ابن عمي أيضًا، ولَقمان العجوري (38 عامًا). أخبروني أيضًا أن شاحنة مساعدات صدمت ابني عبد الرؤوف فأصيب في ساقه اليمنى، وأن ابني الثاني، عامر، أصيب بطلق ناري في فخذه الأيمن وقد أصيب كلاهما عندما ذهبا لإحضار طرود المساعدات من \"منطقة زيكيم\" لعائلتي، التي بقيت بدون معيل أخبروني أيضًا أن شقيق زوجتي، هاني علي صالح (20 عامًا) استشهد في\"زيكيم\" لم يعد لديناً منزل نسكن فيه رأيت بأم عيني الدمار الواسع في قطاع غزة وسمعت عن عمليات القتل الجماعي التي قُتل فيها العديد من سكان القطاع.\r\nحتى اليوم، ما زلت أعاني من آلام شديدة نتيجة للضرب الذي تعرضت له كما أعاني أيضًا من آلام شديدة في فتحة الشرج وأحيانًا ينزف الدم منها، وخاصة عندما أكون في الخارج أو جالسًا على كرسي، وهذا يسبب لي إحراجًا شديدًا ما زلت أشعر بالحزن الشديد بسبب التعذيب والتجارب القاسية التي مررتْ بها أثناء فترة الاعتقال  ذكريات صعبة من شأنها أن تسبب الألم لأي إنسان.', '1776034393_قصة تامر.jpeg', 'صرخات تحت وطأة التعذيب الجنسي '),
(4, 13, 'نسيم الرضيع ', 'حتى اندلاع الحرب كنت اسكن مع زوجتي، شروق المصري (32 عامًا) وأطفالنا الأربعة: محمد (9 أعوام) وشيماء (7 أعوام) وسما (4 أعوام) وصِبا (3 أعوام)، في شقة داخل مبنى مكون من ثلاثة طوابق تملكه عائلتي، في شارع الرضيع في بيت لاهيا، شمال قطاع غزة كانت حياتنا هادئة ومليئة بالحب والدفء الأسري لم يكن بيتنا مجرد سقف يحمينا، بل كان مصدر أمان وطمأنينة كانت لدينا مزرعة وكنت أعمل مزارعًا فيها، وكذلك أجيرًا في مزارع أخرى وأعيل أسرتي.\r\nفي صباح يوم السبت الموافق 7.10.23، نحو الساعة 6:30، استيقظت مفزوعًا على دويّ الانفجارات بينما كانت زوجتي تُحضّر شيماء ومحمد للذهاب إلى المدرسة. نظرت من النافذة فرأيت المقاومة الفلسطينية تطلق وابلا كثيفًا من القذائف باتجاه إسرائيل. فتحت التلفاز وتابعت الأخبار عبر الإنترنت وفهمت أنه يجدر بنا البقاء في البيت وعدم الخروج.\r\nبقينا في منزلنا حتى يوم الخميس الموافق 12.10.23، قرابة الساعة 18:00، حين بدأت طائرات جيش الاحتلال بقصف بنايتنا بشكل مباشر دُمّر جزء كبير من البناية استشهدت عمّتي سلوى الرضيع (50 عامًا) وأَصيبت أمي، هيام الرضيع (55 عامًا) إصابة خطيرة وابنتي سما إصابة طفيفة، بسبب القصف اضطرت عائلتي للنزوح إلى مدرسة خليفة بن زايد التابعة لوكالة الأونروا في مشروع بيت لاهيا كما لجأت عائلة زوجتي إلى المكان نفسه سكنّا في أحد الصفوف الدراسية وكانت الظروف سيئة جدًا اضطررنا إلى تدبر أمورنا من دون تلبية أبسط مقومات الحياة الإنسانية لم يكن هناك ما يكفي من الطعام أو الماء ولم تتوفر لدينا ملابس للتبديل ولا فرشات ولا بطانيات.\r\nفي 6.12.23 تعرّضت المدرسة لهجوم استشهد عمّ زوجتي محمود المصري رغم ذلك، اضطررنا إلى البقاء لعدم وجود مكان آخر نذهب إليه ثم في مساء يوم السبت الموافق 9.12.23، وبينما كنا جميعًا في المدرسة، طوّقها الجيش الإسرائيلي ب \"حزام ناريّ\" من القصف كنا جميعًا في حالة خوف شديد انتشرت الآليات الثقيلة ومركبات الجيش الإسرائيلي حول المدرسة وتمركز قناصة منه على أسطح المباني المرتفعة المحيطة بها وبعد وقت قصير، اقتحم جنود الاحتلال المدرسة وأمروا جميع الموجودين بالنزول إلى الساحة في ساحة المدرسة فصلوا بين النساء والرجال. جمعوا الرجال من عمر 15 إلى 55 في جهة، والنساء والأطفال وكبار السن في جهة أخرى كنا جميعًا خائفين ومتوترين للغاية في مرحلة ما أمرنا الجنود نحن الرجال، بخلع ملابسنا والبقاء بالملابس الداخلية شعرت بإهانة شديدة حين أجبرت على فعل ذلك أمام كل هؤلاء الناس وخاصة أمام زوجتي وأطفالي.\r\nبعد ذلك ساق الجنود الرجال بمجموعات من خمسة أشخاص في كل مجموعة إلى مسجد \"شادي حبّوب\"، شمال المدرسة هناك، قيدوا يديّ خلف ظهري بأربطة بلاستيكية بشكل مؤلم جدًا وساقونا مشيًا إلى معسكر للجيش قرب مستشفي حمودة للولادة في الشارع الرئيسي في بيت لاهيا كانت تحيط بنا مركبات عسكرية وعدد كبير من الجنود.\r\nفي معسكر الجيش، أوقفوني أمام كاميرا وصوّروني للتعرّف على الوجه، ثم أمروني بالجلوس قرب سياج من الأسلاك الشائكة، وهناك صوّرني أحد الجنود بهاتفه أيضًا بعد ذلك أدخلوني إلى إحدى مركبات \"الهامر\" وكان في داخلها ضابط دقّق الضابط في بياناتي الشخصية ثم قال لي \"أهلًا وسهلًا\" بعدها، أعطوني بنطالًا وقميصاً لأرتديهما وغطّوا عينيّ ودفعوني بعنف إلى داخل شاحنة، وسط وابل من الشتائم مثل \"يا ابن الشرموطة\" و\"يا ابن القحبة\" صعد إلى الشاحنة معتقلون آخرون ثم انطلقت، في الطريق، كان السائق يقود بسرعة كبيرة، عمدًا على ما أظن، ثم يقوم بتوقفات مفاجئة، فكنّا نصطدم ببعضنا بعنف، عندما توقفت الشاحنة في النهاية، أنزلونا وأوقفونا في طابور بين صفّين من الجنود وراحوا يضربوننا، واحدًا تلو الآخر، ويشتموننا لاحقًا، أخذونا إلى ساحة مكشوفة وتركونا هناك حتى الصباح، تحت المطر وفي البرد شعرت بأن قلبي سيتوقف من شدة الخوف والبرد.\r\nفي الصباح فتّشونا ثم ساقونا إلى حافلة سارت قرابة ساعتين ثم توقفت لم نكن نعرف إلى أين وصلنا أنزلونا من الحافلة وهم ينهالون علينا ضربًا، ثم أدخلونا إلى قفص ونزعوا العصبات عن أعيننا والقيود عن أيدينا بعد ذلك أعطوا كل واحد منا بنطالًا وقميصًا باللون الرمادي وطلبوا منا تبديل الملابس وبعد أن بدّلنا، أخذونا إلى العيادة، حيث سألني الطبيب إن كنت أعاني من أمراض مزمنة ثم أعادوا تغطية عينيّ وتقييد يديّ أخذونا إلى بركس كبير كان يضم عددًا كبيرًا من المعتقلين هناك علمت أنني محتجز في سجن \"سديه تيمان\".\r\nفي صباح اليوم التالي أجروا العَدّ ثم قدّموا لنا وجبة إفطار شملت خبزًا وعيّنات صغيرة من اللبنة والمربى وفي الغداء قدّموا خبزًا مع عينات من التونة، وكانت وجبة العشاء مشابهة لوجبة الإفطار، في صباح 11.12.23 أثناء العدّ، نادوا باسمي ورقمي ثم بدأوا بسحبي إلى مكان آخر وهم يضربونني ضربًا شديدًا وصلنا إلى غرفة كانت أرضيتها مغطاة بالقش كان هناك ضابط وجندي، أمراني بخلع كل ملابسي وارتداء حفاض ثم قيّدوا يديّ خلف ظهري وغطوا عينيّ وعلّقوني (وضعية \"الشبح\") على رافعة بالسلسلة (بلانكو) من النوع الذي يستخدمه الجزارون لرفع الخراف بعد الذبح تركوني معلّقًا هناك قرابة 10 ساعات متواصلة كنت أعاني من آلام شديدة في الكتفين ومفاصل اليدين. علّقوا إلى جانبي، بالطريقة نفسها شابًا، آخر أعرفه كانوا يضربوننا ونحن معلّقان، خصوصًا في منطقة الصدر مع كل ضربة كنت أشعر أن روحي تكاد تخرج من جسدي من شدة الألم بعد ذلك أنزلوني وأخذوني إلى غرفة كان فيها رجل أصلع ضخم الجثة بلباس مدني، كان جالسا أمام حاسوب وعرّف نفسه بأنه \"من الشاباك\" قبل بدء التحقيق قيّدوني إلى كرسي في البداية طلب مني تفاصيل شخصية عني وعن أفراد أسرتي. ثم ادّعى أنني مقاتل في حماس وأنني عبرت الحدود في 7 تشرين الأول 2023 أنكرت ذلك سألني أين يُحتجز المخطوفون الإسرائيليون، فأجبته بأنني لا أعرف عندها بدأ المحقّق يهدد بقتل زوجتي وأطفالي، وقال لي أيضًا: \"إذا أصريت على عدم الاعتراف وعدم الكلام، فسنجعلك تتكلم من مؤخرتك\" استمر التحقيق قرابة ساعة، ثم أعادوني إلى غرفة \"الشبح\" وعلّقونى مرة أخرى.\r\nاستمر التعذيب بكافة الأشكال وأبشع الطرق حتى نقلوه إلى زنزانة لم يكن نسيم الرضيع يحلم بالكثير وهو في زنزانته لم يحلم بالحرية بمعناها الكبير، ولا بسماء مفتوحة أو بحر غزة الذي اشتاق له بل حلم بسيط حدّ الوجع: أن يرى عائلته فقط ومضى عامان كاملان وهو يعدّ الأيام لا بالتقويم، بل بالشوق والانتظار.\r\nداخل الزنزانة، لم يكن هناك أقلام ولا أوراق ومع ذلك، رفض الأسرى أن تصمت قلوبهم نزعوا قطع قماش من ملابسهم المهترئة، وبردوا سلكًا نحاسيًا حتى صار إبرة، وسحبوا خيوطًا واهنة من أطراف ثيابهم، بالخيط والإبرة كتبوا ما عجز الصوت عن قوله: أسماء أحبّتهم، تواريخ، قلوب صغيرة، ورسائل شوق مطرّزة بالصبر نسيم كان واحدًا منهم. طرّز لوالدته قلوبًا كثيرة، وكأنه يخشى أن لا تكفي كتب اسم والده مرارًا، وحلم أن يخرج بتلك القطع القماشية إلى زوجته وأطفاله الثلاثة، هدايا بسيطة لكنها محمّلة بعامين من الاشتياق.\r\nيقول نسيم: “ابنتي صبا كانت تزحف حين اعتُقلت، واليوم صارت تمشي وتلعب وتضحك.” احتفظ بالقطع بعناية، خبّأها كمن يخبّئ عمره، وحين خرج نسيم من السجن، وصل إلى مستشفى ناصر، يحمل تلك القطع المطرّزة ككنز صغير كان يبحث عن الوجوه التي كتب أسماءها بالخيط، عن الأصوات التي عاش عليها في ليله الطويل هناك، سقط كل شيء دفعة واحدة الفاجعة كانت كاملة عائلته كلّها استُشهدت لم يبقَ له إلا ابنته سما… وذاكرة مثقلة بالفقد. \r\nفقد نسيم والده وفقد زوجته وأطفاله الثلاثة لم يتبقى له سوى طفلته سما الناجية الوحيدة حاملة بقلبها البرئ صاحبة ال5 سنوات صدمة ووجع لا يمكن تجاوزه أو نسيانه. \r\nاليوم، يحمل نسيم سما،، ويشدّها إلى صدره لا تكاد تفارقه، كأنه يخاف أن يخسرها كما خسر كل شيء يطعمها بيديه، يلفّها بغطاء دافئ، ويبتسم لها كثيرًا، كأنه يحرس آخر ما تبقّى له من العالم، سما هي الناجية الوحيدة، أما الهدايا فما زالت قطع قماش صامتة، مطرّزة بالخيط والغياب، تشهد على أسير خرج حيًّا من السجن… ليكتشف أن من كان ينتظرهم، لم يعودوا موجودين.', '1776036343_نسيم الرضيع.jpg', 'هدايا مطرزة بالخيط والغياب '),
(5, 13, 'محمود أبو فول ', ' في واحدة من أوجع حكايا الأسرى المحررين في صفقة التبادل قبل أيام، تنفس الأسير محمود أبو فول الحرية لكنه لم يرها، حيث خرج من سجون الاحتلال الإسرائيلي لا يحمل سوى آثار التعذيب على جسده، وعينين مطفأتين إلى الأبد، خرج الشاب العشريني إلى النور دون أن يعرفه، وعانق والدته دون أن يبصر وجهها، حرّ لكن بألم مقيم، على كرسي متحرك، بقدم واحدة وبصر مفقود وذاكرة مثقلة.\r\nفي 27 ديسمبر/ كانون الأول 2024، اعتقلت قوات من الجيش الإسرائيلي أبو فول من على سرير المرض يتلقى العلاج بـ\"مستشفى كمال عدوان\" بمحافظة شمال قطاع غزة، بعد اقتحامها له واحتجازها المرضى والطواقم الطبية، ورغم تردي وضعه الصحي آنذاك، تعرض للاعتقال وخضع للتحقيق الإسرائيلي الذي تخلله \"التعذيب والضرب والإهانة والشتم\"\r\nفقد أبو فول بصره في غرف التحقيق بعد أن لفق له ضباط المخابرات تهما لا صلة له بها، ويقول \"طلبوا مني أن أعترف بتهم لا أساس لها من الصحة، وعندما رفضت انهالوا على رأسي ضربا حتى فقدت الوعي، ولما أفقت حاولت فتح عينيّ مرارا، لكنني لم أرَ شيئا، كل شيء كان أسود، فأدركت أني صرت أعمى\"، لم يتوقف تعذيبه الجسدي والنفسي عند ذلك، ففي أقبية التحقيق أيضا كسر الضابط عموده الفقري وعظام قفصه الصدري، وحُرم من العلاج والجراحة اللازمين حتى تدهورت حالته الصحية، لتضيف إسرائيل لجسده خسارة جديدة، كان أولها ساقه المبتورة التي فقدها قبل سنوات في عدوان سابق على غزة، لم يصدّق كلام السجان بأن اسمه ضمن قوائم الأسرى المقرر الإفراج عنهم، فظنها إحدى خدع التحقيق تماما ككذبة تصفية عائلته التي أخبره بها المحقق ونفاها له أحد الأسرى الذين وصلوا إلى السجن مؤخرا، لكن رجاء واحدا كان يجتاح تفكيره \"ليتني أستعيد بصري للحظة فقط لأراهم\".\r\n', '1776036910_محمود أبو فول.jpg.webp', 'تنفس الحرية... لكنه لم يراها '),
(6, 13, 'هيثم سالم', 'عندما اندلعت الحرب، كنت أسكن مع زوجتي، إخلاص عيسى (32 عامًا) وأطفالنا الثلاثة، براء سالم (8 أعوام) وإيمان (5 أعوام) وليان (عامان)، في الطابق الرابع في مبنى مكون من أربعة طوابق في بيت لاهيا، قريبًا جدًا من مخيم جباليا في الشقق الأخرى في المبنى كان يسكن أبناء أعمامي في البداية لم نغادر منزلنا كنت أعتقد أن الحرب ستنتهي بعد بضعة أيام  إلى أن أدركت أنه لا يمكن مقارنتها بالحروب السابقة.\r\nفي كانون الأول 2023، هاجم الجيش بيت لاهيا وأصيب منزلنا اضطررنا إلى النزوح وانتقلنا إلى منزل عائلة زوجتي في مخيم جباليا للاجئين بقينا عندهم بضعة أيام، ثم انتقلنا مرة أخرى، وهذه المرة إلى مقر وكالة الأونروا في غرب مدينة غزة بقينا هناك خمسة أيام ثم عدنا إلى منزل عائلة زوجتي من حينٍ لآخر، كنت أتمكن من زيارة منزلنا في بيت لاهيا، والذي دمرته عمليات القصف جزئياً. في شباط 2024، بعد عدة أشهر من التهجير، أصلحت الأضرار قدر المستطاع وعُدنا للعيش في منزلنا كما عاد أفراد آخرون من عائلتنا للعيش في المبنى.\r\nخلال الاجتياح الثاني لمخيم جباليا، في أيار 2024، هاجم الجيش الإسرائيلي المنطقة المحيطة بمستشفى كمال عدوان، والقائم في بيت لاهيا، ليس بعيدًا عن منزلنا أصيبت بنايتنا إصابة مباشرة بصاروخ اخترق الطابق الذي كنا نسكن فيه وانفجر في الطابق الثاني استشهد حوالي 25 فرداً من عائلتي الموسعة نجوت أَنا وزوجتي والأطفال من القصف وبقينا سالمين نزلنا إلى الطابق الثاني كان المنظر هناك مروّعاً: جثث وجرحى في كل مكان. في ذلك اليوم، انتقلت مع زوجتي وأولادي إلى منزل خالتي في مخيم جباليا للاجئين وبقينا هناك حوالي أربعة أشهر ثم انتقلنا من هناك إلى شقة جارنا الذي انتقل إلى الجنوب وأقمنا فيها نحو شهر، حتى تشرين الأول 2024، عندما اقتحم الجيش مخيم جباليا للاجئين مرة أخرى خاطبنا الجيش عبر مكبرات الصوت وأمرنا بالتوجه إلى حاجز \"الإدارة المدنية\" الواقع شرق مخيم جباليا، ذهبت أنا وزوجتي والأطفال نحو الحاجز كان الأطفال يبكون دون توقف وكانت زوجتي خائفة جداً كانت تقول لي طوال الوقت: \"هيثم، أنا خائفة جدًا من أن يعتقلك الجيش عند الحاجز. إذا أخذك الجيش، فسأموت بدونك\" بسبب خوف زوجتي وأطفالنا، قررنا العودة على أعقابنا وعدم المضي قُدمًا إلى الحاجز، عدنا إلى مخيم جباليا، إلى منزل أخي لكن القصف لم يتوقف، بل اشتد من حولنا، ونثر الجيش منشورات تأمرنا بالإخلاء في النهاية، في 1711.24، قررنا الذهاب إلى حاجز الإدارة المدنية عندما وقفنا عند الحاجز، كانت زوجتي تبكي من شدة الخوف أعطيت ابني براء ساعة اليد الخاصة بي بدأ يبكي وقال لي: \"أنا سعيد جدًا لأنك أبي، وأنا أحبك\".\r\nعانقت أطفالي وقبلتهم في ذلك الوقت، شعرت بأنهم سيلقون القبض عليّ، في تلك اللحظة، ناداني الجنود عند الحاجز اقتربت منهم، فصوروني وأعطوني زيًا أبيض لأرتديه بدأوا بضربي على الفور وشعرت بأنهم يحطّمون جسدي، في المساء أخذوني أنا وبقية المعتقلين في شاحنتين إلى منطقة تحولت إلى معسكر للجيش إلى الشرق من مخيم جباليا للاجئين كنا جميعا مقيدين بالأصفاد والأغلال في أيدينا وأرجلنا عندما وصلنا إلى المعسكر، أجبرنا الجنود على الركوع وطأطأة رؤوسنا إلى الأسفل، ثم فركوا رؤوسنا بالحصى وركلونا كنت أرتجف من البرد. اقتربت مني جنديّة، فقلت لها إنني أشعر بالبرد ذهبت وعادت مع بطانية لم يحصل بقية السجناء على بطانيات، قضينا الليلة هناك، في الصباح وصلت حافلة أدخلونا إليها وضربونا أثناء ذلك نقلونا إلى سجن \"سديه تيمان\" عندما وصلنا إلى السجن، لم أستطع التبول بسبب الضرب الذي تعرضت له لاحقًا، لاحظت وجود دم في البول فحصني طبيب وأخبرني أنه لا يوجد علاج ونصحني بشرب الماء.\r\nأخضعوني للتحقيق طوال الوقت أثناء التحقيق، كان الجنود يضربونني ضربًا مبرحًا وقد كسروا إحدى أضلاعي حاول الجنود طوال الوقت تخويفنا وكسر معنوياتنا كانوا يقومون بعمليات قمع مرتين في الأسبوع، يلقون قنابل صوتية في الغرف، يصيبون السجناء بجروح، يجبروننا على الركوع وأيدينا فوق رؤوسنا ويشتموننا عيَّنني الجنود\"شاويشًا\" أي مسؤولاً عن بقية السجناء، وأمروني بصفع السجناء الآخرين قالوا لي \"إذا لم تضرب السجناء، فسنضربك نحن\"، وعندما صفعت السجناء طلبت منهم السماح رغم ذلك ضريني الجنود وشتموني كانت تلك أصعب أيام في حياتي لم يكن هناك رحمة أو شفقة تجاه أى سجين.\r\nبالإضافة إلى كل ذلك، كنا نعاني من قلة الطعام في الصباح كنا نحصل على شريحة صغيرة من الخبز وقطعة تفاح أو خيار أو بندورة، في الظهيرة، كنا نحصل على ملعقة من التونة مع شريحة خبز أحيانًا كانوا يعطوننا أيضًا ملعقة من المربى، عندما كان الجنود يجلبون لنا الطعام، كانوا يضعونه تحت الباب ثم يدفعونه بأحذيتهم أحيانًا، كانوا يسكبون صابون الجلي أو الماء على طعامنا ويجبروننا على أكله - وإذا رفضنا، كانوا يضربوننا، أحيانًا كان الطعام يصل مبللًا بمياه الأمطار كان الجنود يقولون لنا: كلوا مثل الطيور والحيوانات.\r\nأحيانًا، كانوا يطلقون علينا الكلاب لتهاجمنا، يضربوننا بألجمة أفواه الكلاب الحديدية، وحتى يتبولون علينا كانوا يسمحون لنا بالاستحمام مرتين فقط في الأسبوع في البداية كانوا يسمحون لنا بتغيير ملابسنا بعد 40 يوماً، وبعد ذلك بعد ثلاثة أشهر فقط.\r\nبقيت في سجن \"سديه تيمان\" حوالي أربعة أشهر ونصف الشهر، حتى 9.4.25. ثم  نقلوني إلى سجن عوفر، في سجن \"عوفر\" كان العديد من السجناء يعانون من الجرّب والالتهابات الفطرية كما أصبت بها أنا أيضاً لم نتلق أي علاج - كلما طلبنا دواءً للجرب والالتهابات، كانوا يقولون لنا أن نغسل الجلد بالماء والصابون في إحدى المرات، حصلنا على الكلور وقام بعض السجناء بغسل الجلد المصاب به من شدة اليأس، لكن ذلك زاد من حرقة الجلد، فقمنا بصب الماء البارد عليهم. ظل بعض السجناء يعانون من الجرب طوال أشهر: احمرت بشرتهم ونزفت من كثرة الحكّ ولم يتمكنوا من النوم ليلاً كانت الحكة شديدة لدرجة أن بعض السجناء نزعوا شعر أجسادهم في المناطق الحساسة - نزفوا وصرخوا من شدة الألم ليلاً ونهاراً.\r\nفي سجن \"عوفر\" أيضًا كان الطعام قليلًا جدًا كنا نحصل على حصص صغيرة جدًا من الخبز والبيض، كانت تكفي فقط لإبقائنا على قيد الحياة كانوا يضربوننا ويقمعوننا دون توقف أحيانًا كنت أبكي من شدة الضربات التي كنت أتلقاها على جميع أنحاء جسدي، وخاصةً لأنني كنت لا أزال أعاني من كسر في الضلع، حتى الاستحمام كان كابوسًا كانوا يُدخلون خمسة سجناء معًا إلى الحمّام، وبعد دقيقة يصرخون علينا للخروج لم نكن نحصل إلا على صابون الجلي للاستحمام، في الشتاء كان الجنود يوقظوننا في منتصف الليل أحيانًا للاستحمام . كان ذلك تعذيبًا أكثر منه استحمامًا.\r\nفي 25.8.25، نقلوني إلى سجن النقب (كتسيعوت)، خلال النقل، ضربوني، كان الطعام في \"كتسيعوت\" أفضل منه في \"سديه تيمان\" و\"عوفر\" كانت الكميات قليلة ولا تشبع، لكن الطعام كان أكثر تنوعًا كنا نحصل على البيض وصدور الدجاج والفاصوليا والعدس والخبز والحمص، لكننا لم نكن نشبع هناك أيضًا، كنا نعيش على القليل جدًا، وفي أيام السبت كنا نحصل على قطعة صغيرة من الجبن والزيتون، ما كان للمرضى سوى انتظار رحمة الله لم يكونوا يحصلون على أدوية، باستثناء الأشخاص الذين يعانون من أمراض مزمنة.\r\nفي 5.10.25، أبلغتني إدارة السجن بأنه سيُفرج عني ونقلوني إلى قسم آخر، كنت سعيدا جداً بالإفراج وبأنني سوف ألتقي عائلتي أخيراً، تذكرت أن عيد ميلاد ابنتي ليان هو في 1710، فصنعت لها هدية كانت عبارة عن سوار وخاتم من الخرز،قبل الإفراج فحصني الطبيب أنا وبقية السجناء وقاس طولنا ووزننا أخذونا من هناك إلى غرفة التحقيق التابعة لجهاز \"الشاباك\" حيث وجهوا لنا أسئلة شخصية: عن أنفسنا، عن عائلاتنا وعن اعتقالنا في 12.10.25، قبل يوم من إطلاق سراحي، جاء ممثلون عن الصليب الأحمر وطلبوا منا ملء استبيان قبل إطلاق سراحنا رفضنا ملء الاستبيان وتساءلنا لماذا لم يأتوا قبل ذلك.\r\nفي اليوم التالي، 13.10.25، قيدوا أيدينا وأرجلنا ووضعونا في حافلات نقلتنا إلى معبر كرم أبو سالم (كيرم شالوم) هناك أزالوا الأصفاد عنّا دخلنا إلى القطاع ثم نقلونا في حافلة أخرى إلى مستشفى ناصر في خان يونسٍ كنا سعداء ومتحمسين للغاية كنا حوالي 50 سجيناً تم الإفراج عنهم، وفي المستشفى كان هناك أشخاص في انتظارنا استقبلونا بالفرح والتصفيق كان من المفترض أن يكون ذلك أفضل يوم في حياتي...\r\nاجتمع الجميع بعائلاتهم، إلا أنا فقط نظرت حولي فلم أجد أحداً من أفراد عائلتي أخيراً رأيت محمد، أحد أبناء أعمامي سألته: \"أين عائلتي؟ لم أر منهم أحداً هل عائلتي بخير؟\" فأجابني بنعم تابعت وسألته: \"وماذا عن زوجتي وأولادي؟\"، فقال لي: \"تذكر اللّٰه يا هيثم\" لم أفهم ماذا يعني، فسألته مرة أخرى عن زوجتي وأولادي طلب مني محمد أن أتحلى بالصبر ذهب، ثم اقترب مني شاب آخر من عائلتي. قال لي إن زوجتي وأولادي بين يديّ اللّه وأنهم جميعًا قد استشهدوا عندما سمعت هذا الخبر، شعرت وكأن صاعقة قد أصابتني في قلبي وعقلي شعرت أن حياتي قد توقفت كان ذلك أسوأ يوم في حياتي، في وقت لاحق من ذلك اليوم، التقيت بوالدي وإخوتي كنت في حالة نفسية صعبة وشعرت بأنني أنهار أخذوني معهم إلى مخيم المهجرين الذي يعيشون فيه، في دير البلح كانت الأجواء كئيبة وحزينة على موت زوجتي وأولادي أنا الآن أعيش في خيمة مع والديّ وأحد إخوتي عدت من الاعتقال لأجد أنني فقدت زوجتي وأولادي فقدت منزلي أيضاً فقدت كل شيء أبقى في الخيمة طوال الوقت ولا أذهب إلى أي مكان أعيش على ذكريات زوجتي وأولادي أشعر بأنني أصبحت جسماً بلا روح.\r\n*إخلاص عيسى (32 عامًا)، زوجة هيثم سالم، وابنتاهما إيمان (5 أعوام) وليان (عامان) استشهدن في غارة إسرائيلية على الخيمة التي كانوا يعيشون فيها في حي الشيخ رضوان في مدينة غرة في 8 أيلول 2025 ابنهما براء (8 سوات) أصيب في الغارة و استشهد متأثراً بجراحه بعد بضعة أيام، في 12 أيلول، أي استشهدت عائلته قبل شهرٍ واحد من الافراج........ ', '1776038806_هيثم سالم.jpeg', 'عودة مثقلة بصدمة الفقد'),
(7, 14, 'ماهر نسيم ', 'ماهر نسيم أحد النازحين من بيت حانون يؤكد أن معاناة الأطفال بلغت حدا لا يُطاق، في ظل عجز العائلات عن توفير الطعام أو المياه، ويشير إلى أن البالغين غالبا ما يضطرون إلى الاكتفاء بالماء لتسكين آلام الجوع، في محاولة يائسة للصمود، بينما يعجزون عن تفسير ما يحدث لأطفالهم الذين لا يجدون ما يسدّ رمقهم، ويضيف نسيم أن الحالة النفسية لأطفاله بدأت في التدهور، إذ باتوا يطرحون أسئلة مؤلمة تعكس يأسهم من الحياة، في ظل واقع حرمان مطبق لم يعد يفرق بين صغير وكبير.', '1776039418_ماهر نسيم.jpg.webp', 'أطفال ينامون جوعى'),
(8, 14, 'حسن أبو شغيبة', 'حسن أبو شغيبة، وهو رب أسرة فقد مصدر دخله، فيؤكد أن عائلته اضطرت إلى تناول ما لا يؤكل في الظروف الطبيعية، ويشير إلى أنهم استهلكوا لحم الحصان في غياب البدائل، واكتفوا بالملح في بعض الأيام، وسط عجزه عن تأمين الغذاء لطفله المصاب بإعاقة شديدة، ويصف الوضع بأنه \"كارثي بكل المقاييس\"، ويحمّل الاحتلال الإسرائيلي مسؤولية إيصال الأهالي إلى هذه المرحلة من المجاعة والحرمان، نتيجة الحصار المستمر والهجمات العسكرية التي ضربت البنية التحتية والمراكز الإنسانية.', '1776039570_حسن أبو شغيبة.jpg.webp', 'مساوئ البدائل لا تطاق '),
(9, 14, 'أبو عز زويدي ', 'يروي أبو عز زويدي كيف غيّر الجوع ملامح الناس، حتى أصبح من الصعب التعرف على الوجوه، بمن فيهم أقرب الأقربين، ويقول إن شدة المعاناة تركت آثارها النفسية والجسدية على الجميع، وإن كثيرين فقدوا القدرة على التمييز بين الليل والنهار وسط مشهد النزوح والجوع المتواصل، ورغم كل ذلك، يؤكد زويدي أن الأهالي ما زالوا متمسكين بالصمود والثبات، ويرون في بقائهم في غزة موقفا من المقاومة، حتى لو كلفهم ذلك مواجهة الجوع والمرض والموت.', '1776039715_أبو عز زويدي.jpg.webp', 'تغيير الجوع للملامح '),
(10, 15, 'حسام أبو صفية', 'ولد حسام إدريس أبو صفية -وكنيته \"أبو إلياس\"- يوم 21 نوفمبر/تشرين الثاني 1973 في مخيم جباليا بمحافظة شمال قطاع غزة لعائلة هُجّرت عام 1948 من بلدة حمامة الواقعة في قضاء عسقلان، يعد أبو صفية إحدى الشخصيات البارزة في المجال الصحي، وهو أحد قادة الفرق الطبية في قطاع غزة، نال درجة الماجستير وشهادة البورد الفلسطيني في طب الأطفال وحديثي الولادة، وشغل منصب مدير مستشفى كمال عدوان شمال القطاع.\r\nفي 5 أكتوبر/تشرين الأول 2024 فرض الجيش الإسرائيلي حصارا خانقا على محافظة شمال قطاع غزة، ومنع دخول الطعام والماء، كما شن غارات جوية وقصفا متواصلا، مما أسفر عن مجازر بحق المدنيين في المنطقة، وقد حدّ حصار الشمال من عمل المستشفيات في المناطق المحاصرة، ومنها مستشفى كمال عدوان، ورغم ذلك فإن أعضاء الكادر الطبي المكون من طبيبين -أحدهما أبو صفية- وعدد قليل من الممرضين واصلوا أداء واجبهم الإنساني، ورفضوا الانصياع لأوامر الجيش المتكررة لإخلاء مباني المستشفى ومغادرة المحافظة رغم استمرار اعتداءاته بحقهم، اقتحمت قوات الجيش الإسرائيلي يوم 25 أكتوبر/تشرين الأول 2024 مستشفى كمال عدوان، واعتقلت مديره حسام أبو صفية مع مئات المصابين والطواقم الطبية، وبعد إفراجها عنه تلقى خبر استشهاد ابنه إلياس في غارة إسرائيلية، وفي 24 نوفمبر/تشرين الثاني من العام نفسه أصيب أبو صفية جراء استهدافه من مسيّرة إسرائيلية أثناء خروجه من غرفة العمليات، وأوضح أنه أصيب بـ6 شظايا اخترقت منطقة الفخذ سببت تمزقا في الأوردة والشرايين، وفي 27 ديسمبر/كانون الأول 2024 اقتحمت قوات الاحتلال مستشفى كمال عدوان المحاصر واعتقلت أبو صفية، وانتشرت له صورة قبل اعتقاله تظهره وهو يمشي وسط ركام المستشفى الذي أحرقه الجيش الإسرائيلي وفي وجهه دبابات الاحتلال، واتهم المدير العام لوزارة الصحة الفلسطينية في القطاع منير البرش الاحتلال بخداع الطاقم الطبي الذي أوحى له أنه سيذهب إلى المستشفى الإندونيسي، لكنه أخذ أفراده إلى مكان آخر واعتقلهم جميعا، من بينهم حسام أبو صفية، وأكد أن أبو صفية تعرّض لضرب مبرح بالهراوات والعصي من قوات الاحتلال الإسرائيلي التي أجبرته على خلع ملابسه وألبسته لباس المعتقلين، وأن الاحتلال اتخذه درعا بشرية، وفق من أُفرج عنهم لاحقا.\r\nوقد أفادت محامية الطبيب حسام أبو صفية والمعتقل لدى إسرائيل منذ 27 ديسمبر/كانون الأول 2024 بأن حالة موكلها الصحية شهدت تدهورا خطيرا حيث فقد نحو 40 كيلوغراما من وزنه، وأضافت محاميته -خلال الأشهر الماضية- أن الدكتور المعتقل يعاني من اضطرابات في دقات القلب دون أن يتلقى أي علاج، وأكدت أنه يتعرض للتعذيب والضرب الشديد، ويقبع في زنازين العزل تحت الأرض في ظروف اعتقال قاسية تشمل التجويع والإهمال الطبي الممنهج، كما قالت وزارة الصحة في غزة إن أبو صفية يعاني من وضع صحي صعب وسط حرمان متعمد من العلاج، مشيرة في بيان أن محامية أبو صفية أفادت بـ\"حرمانه المتعمد من العلاج\"، ووصفت الانتهاكات التي يتعرض لها داخل السجون بـ\"الوحشية\"، مؤكدة تعرضه \"للضرب المتواصل خلال التحقيق\"، كما أوردت تقارير عن عائلة أبو صفية منتصف أكتوبر/تشرين الأول الماضي، نقلا عن الفريق القانوني للطبيب، أن محكمة إسرائيلية \"أجّلت المراجعة القانونية له لمدة 6 أشهر\"، وقد أمضى أبو صفية يومها نحو 10 أشهر في الاعتقال الإسرائيلي، وفي فبراير/شباط 2025، ظهر الطبيب أبو صفية لأول مرة في تسجيل بثّته وسائل إعلام إسرائيلية مقيّدًا داخل السجن، مما أثار موجة تنديد واسعة اعتبرت المشهد شكلا من “الإرهاب النفسي” متعمّدًا لإذلاله.\r\n', '1776069506_حسام-أبو-صفية-1729143557.jpg.webp', 'طبيب الأطفال الذي مشى نحو الدبابة'),
(11, 16, 'صالح الجعفراوي ', 'ولد صالح عامر الجعفراوي في 22 نوفمبر/تشرين الثاني 1998 بقطاع غزة، وهو حافظ لكتاب الله تعالى، وعرف بترتيله العذب -كأبيه- على منصات التواصل الاجتماعي، وإنشاده الذي كان يرفع معنويات الغزيين أثناء حرب الإبادة، وكان من أبرز أناشيده أغنيته الشعبية \"قوية يا غزة\"، درس الصحافة والإعلام في كلية الآداب بالجامعة الإسلامية بغزة، وتخرج فيها عام 2019، اشتهر بلعبه تنس الطاولة في طفولته، وبرز فيها وانضم في فترة دراسته الجامعية إلى فريق الجامعة الإسلامية بغزة، وحصل على المركز الأول على مستوى الجامعة الإسلامية لتنس الطاولة عام 2022، وفي الرابع من فبراير/شباط 2023، شارك في بطولة العالم التي أقيمت في دولة قطر ممثلا عن دولة فلسطين.\r\nعمل الجعفراوي مصوراً مستقلاً لعدد من المؤسسات الإعلامية المحلية في غزة، وعرفه الناس أول مرة في مسيرات العودة عام 2018، حين برز إعلامياً شاباً ميدانياً يمتلك حساً صحفياً عالياً وقدرة على الوصول إلى قلب الحدث كما وصفه زملاؤه، وغطى الجعفراوي أحداث مسيرات العودة من الخطوط الأمامية، وأُصيب أكثر من مرة، لكنه واصل المسير.\r\nوبرز أكثر منذ الأيام الأولى للعدوان على غزة واحداً من الأصوات الميدانية، ومن أبرز الوجوه الإعلامية التي اختارت البقاء في قلب الخطر لتوثيق جرائم الاحتلال بحق المدنيين على مدى عامين بعدسته عبر حسابه في إنستغرام، عرفه المتابعون بشجاعته في تغطية القصف والدمار وتنقله بين المستشفيات والملاجئ والمناطق المنكوبة وحصدت مقاطعه مشاهدات عالية، حتى تخطى عدد متابعيه 10 ملايين شخص على إنستغرام، مما تسبب بإغلاق حسابه الشخصي مرات كثيرة، ومنعه من إنشاء حسابات جديدة.\r\nأعلنت وزارة الداخلية والأمن الوطني في قطاع غزة مساء يوم الأحد 12 أكتوبر/تشرين الأول 2025 ميلاديًا الموافق 20 ربيع الآخر 1447 هجريًا، عن وقوع اشتباكاتٍ بين الأجهزة الأمنية الفلسطينية ومليشياتٍ مسلحة في حي الصبرة بمدينة غزة، مما أسفر عن قتلى وجرحى، ليأتي بعدها تأكيدٌ على استشهاد صالح الجعفراوي، كما أشارت مصادر أخرى بأنَّ صالح كان قد اختُطف صباح يوم الأحد 12 أكتوبر 2025 من حي الصبرة بمدينة غزة، على يد عناصر مسلحة مجهولة الهوية، وسط إطلاق نار كثيف تسبب بحالة من الذعر بين السكان. وبعد ساعاتٍ من انقطاع الاتصال به، عُثر على جثمانه في المنطقة ذاتها، وقد أصيب بطلقات ناريةٍ في أجزاء مختلفة من جسده ذكرت فضائية الأقصى بأنَّ الصحفي صالح الجعفراوي لقي حتفه بنيران عصابات مسلحة خلال تغطيته عودة المواطنين إلى مدينة غزة.\r\nوصيته:\r\nبسم الله الرحمن الرحيم الحمد لله رب العالمين، القائل: “وَلَا تَحْسَبَنَّ الَّذِينَ قُتِلُوا فِي سَبِيلِ اللَّهِ أَمْوَاتًا، بَلْ أَحْيَاءٌ عِندَ رَبِّهِمْ يُرْزَقُونَ.” أنا صالح. أترك وصيتي هذه، لا وداعًا، بل استمرارًا لطريقٍ اخترته عن يقين.\r\nيعلم الله أنني بذلت كل ما أملك من جهدٍ وقوة، لأكون سندًا وصوتًا لأبناء شعبي، عشتُ الألم والقهر بكل تفاصيله، وذُقت الوجع وفقد الأحبة مرارًا، ورغم ذلك لم أتوانَ يومًا عن نقل الحقيقة كما هي، الحقيقة التي ستبقى حجة على كل من تخاذل وصمت وأيضا شرف لكل من نصر ودعم ووقف مع أشرف الرجال وأعز الناس وأكرمهم أهل غزة إن استشهدت، فاعلموا أنني لم أغب… أنا الآن في الجنة، مع رفاقي الذين سبقوني؛ مع أنس، وإسماعيل، وكل الأحبة الذين صدقوا ما عاهدوا الله عليه.\r\nأوصيكم أن تذكروني في دعائكم، وأن تُكملوا المسير من بعدي. تذكروني بصدقاتٍ جارية، واذكروني كلما سمعتم الأذان أو رأيتم النور يشقّ ليل غزة. أوصيكم بالمقاومة… بالطريق الذي سرنا عليه، وبالنهج الذي آمنا به. فما عرفنا لأنفسنا طريقًا غيره، ولا وجدنا معنى للحياة إلا في الثبات عليه.\r\nاوصيكم بأبي .. حبيب قلبي وقدوتي، من كنت أرى نفسي فيه ويرى نفسه في .. يا من رافقتني وقت الحرب بكل ما فيها .. أسأل الله أن نلتقي في الجنان وأنت راض عني يا تاج رأسي اوصيكم بأخي ومعلمي ورفيق دربي ناجي، يا ناجي… قد سبقتُك إلى الله قبل أن تخرج من السجن، فاعلم أن هذا قَدَرٌ كتبه الله، وأن الشوق إليك يسكنني، كنت أتمنى أن أراك، أن أضمّك، أن نلتقي، لكن وعد الله حق، ولقاؤنا في الجنة أقرب مما تظن. اوصيكم بأمي… يا أمي، الحياة بدونك لا شيء. كنتِ الدعاء الذي لا ينقطع، والأمنية التي لا تموت. دعوتُ الله أن يشفيك ويعافيك، وكم حلمت أن أراكِ تسافرين للعلاج، وتعودين مبتسمة.\r\nاوصيكم بإخوتي وأخواتي، رضا الله ثم رضاكم غايتي، أسأل الله أن يسعدكم، وأن يجعل حياتكم طيبة كقلوبكم الرقيقة التي طالما حاولت ان اكون مصدر سعادةٍ لها. كنتُ أقول دومًا: لا تسقط الكلمة، ولا تسقط الصورة. الكلمة أمانة، والصورة رسالة، احملوها للعالم كما حملناها نحن. لا تظنوا أن استشهادي نهاية، بل هو بداية لطريقٍ طويلٍ نحو الحرية. أنا رسول رسالةٍ أردت أن تصل إلى العالم—إلى العالم المغمض عينيه، وإلى الصامتين عن الحق. وإن سمعتم بخبري، فلا تبكوا عليّ. لقد تمنّيتُ هذه اللحظة طويلًا، وسألت الله أن يرزقني إياها فالحمد لله الذي اختارني لما أحب.\r\nولكل من أساء إلي في حياتي شتماً أو قذفاً كذباً وبهتاناً أقول لكم ها أنا أرحل إلى الله شهيدا بإذن الله وعند الله تجتمع الخصوم.\r\nأوصيكم بفلسطين… بالمسجد الأقصى… كانت أمنيتي أن أصل فناءه، أن أُصلّي فيه، أن ألمس ترابه. فإن لم أصل إليه في الدنيا، فأسأل الله أن يجمعنا جميعًا عنده في جنات الخلد اللهم تقبّلني في الشهداء، واغفر لي ما تقدّم من ذنبي وما تأخّر، واجعل دمي نورًا يُضيء درب الحرية لشعبي وأهلي.\r\nسامحوني إن قصّرت، وادعوا لي بالرحمة والمغفرة، فإني مضيتُ على العهد، ولم أُغيّر ولم أُبدّل. والسلام عليكم ورحمة الله وبركاته.\r\nأخوكم الشهيد بإذن الله صالح عامر فؤاد الجعفراوي 12/10/2025 هذا ما اوصى بنشره الحبيب صالح عند استشهاده.', '1776070377_صالح الجعفراوي.jpg.webp', 'صوت غزة الذي صمت برصاص الغدر');
