INSERT INTO `team` (`id`, `name`, `role`, `story`, `image`) VALUES
(2, 'هدى جميل جمعة سلامة', 'وسائط متعددة', 'اسمي هدى، ومنذ تلك الليلة لم يعد اسمي مجرد اسم عادي، بل صار يحمل حكاية كاملة عن بيت تركناه على عجل، وعن حياة انقسمت فجأة إلى “قبل” و”بعد”.\r\nفي تلك الليلة لم يكن الخوف فكرة عابرة، كان شعوراً ثقيلاً في الهواء. جلسنا معاً نحاول أن نبدو هادئين، لكن الصمت كان يقول كل شيء. وعندما جاء القرار بالمغادرة، شعرت أن الزمن توقف للحظة… كيف يمكن للإنسان أن يترك بيته دون أن يعرف إن كان سيعود إليه؟\r\nبدأنا نجمع ما استطعنا بسرعة، لكننا اكتشفنا أن الحياة لا تُختصر في حقيبة. وقفنا أمام ذكرياتنا عاجزين: ماذا نأخذ وماذا نترك؟ في النهاية خرجنا بأشياء قليلة جداً… أقل بكثير مما كانت تعنيه حياتنا.\r\nغادرنا دون وداع حقيقي. دون نظرة أخيرة تليق ببيت عاش معنا كل تفاصيلنا. خرجنا وكأننا سنعود بعد ساعات، لكن في داخلنا كان شعور ثقيل يخبرنا أن الرحلة ستكون أطول مما نتوقع.\r\nفي الطريق أدركت أن النزوح ليس مجرد انتقال من مكان إلى آخر، بل فقدان الشعور بالأمان. فجأة تصبح كل الأماكن مؤقتة، وكل الأيام انتظاراً مفتوحاً على المجهول.\r\nفي مكان النزوح تغيرت تفاصيل الحياة كلها. أشياء كانت عادية أصبحت أحلاماً صغيرة: الهدوء، الخصوصية، النوم بلا قلق. أدركت أن التفاصيل البسيطة التي لم ننتبه لها كانت هي الحياة نفسها.\r\nكنت أشتاق لبيتنا بطريقة موجعة. لغرفتي، لزاويتي المفضلة، للأشياء التي كنت أظنها عادية. أدركت أن البيت ليس جدراناً فقط، بل شعور بالانتماء لا يمكن تعويضه.\r\nورغم كل ذلك، لم نفقد الأمل. كان هناك صوت صغير داخلنا يقول إن هذه ليست النهاية. تعلمنا أن نتمسك بالأشياء البسيطة، وأن نصنع من الصبر طريقاً للاستمرار.\r\nاليوم عندما أقول اسمي، أعرف أنني أحمل قصة صمود وانتظار. وأؤمن أن العودة ليست مجرد حلم بعيد، بل وعد نعيش عليه كل يوم.\r\nاسمي هدى… وهذه حكاية نزوح ما زالت مستمرة', '1776504012_huda.png'),
(3, 'نورا أسعد جمال عاشور', 'نظم تكنولوجيا المعلومات', 'من حياةٍ هادئة إلى واقعٍ مختلف\r\nكنت أحب بلادي كثيرًا، وكنت أراها من أفضل الأماكن التي يمكن أن يعيش فيها الإنسان.\r\nجئت إليها من أجل الدراسة، وكنت أشعر بالفخر لوجودي في إحدى جامعاتها القوية. كانت حياتي تسير بشكل طبيعي، مليئة بالأحلام والطموحات، وتعرّفت على أشخاص رائعين أصبحوا أصدقاء مقربين. كانت الأيام بسيطة وجميلة، وكان كل شيء يبدو مستقرًا ومطمئنًا.\r\nلكن كل ذلك تغيّر فجأة…\r\nاندلعت الحرب، ومعها تغيّر كل شيء.\r\nلم تعد الحياة كما كانت، ولم يعد هناك شعور بالأمان. أصبحت الأيام مليئة بالخوف والقلق، وتحولت التفاصيل الصغيرة التي كنا نعتبرها عادية إلى أشياء صعبة المنال.\r\nبدأت المعاناة تظهر بشكل واضح.\r\nكان هناك نقص في الطعام، وأصبحت المجاعة واقعًا يعيشه الناس يومًا بعد يوم. لم تعد الوجبات كافية، وأصبح الحصول على أبسط الاحتياجات تحديًا كبيرًا. ومع انقطاع الكهرباء لفترات طويلة، أصبحت الحياة أكثر صعوبة، خاصة في الليل، حيث يزداد الشعور بالعزلة والتعب.\r\nومع هذه الظروف، بدأ المرض بالانتشار.\r\nضعف التغذية وقلة الإمكانيات الصحية جعلا من التعافي أمرًا صعبًا، وأصبح الجميع يحاول الصمود رغم الإرهاق الجسدي والنفسي.\r\nوفي وسط كل ذلك، لم يعد البقاء خيارًا ممكنًا…\r\nفكان القرار الأصعب: السفر.\r\nلم يكن السفر سهلًا أبدًا.\r\nكان مليئًا بالتعب والخوف وعدم اليقين. الطريق كان طويلًا، والظروف قاسية، وكل خطوة كانت تحمل معها تحديًا جديدًا. لم نحمل معنا سوى القليل، لكننا حملنا في داخلنا الكثير من الذكريات والألم.\r\nوبعد رحلةٍ طويلة ومليئة بالتعب، وصلت أخيرًا إلى عائلتي بسلام.\r\nكانت لحظة مليئة بالمشاعر… راحة بعد خوف، وطمأنينة بعد قلق طويل. شعرت أنني عدت إلى مكان يحتويّني من جديد، رغم أن ما مررت به لم يكن سهلًا أن يُنسى.\r\nبدأت أستعيد توازني تدريجيًا، وقررت أن أُكمل تعليمي مهما كانت الظروف.\r\nلم يكن الأمر سهلًا، لكنني تمسكت بحلمي، لأنني كنت أؤمن أن العلم هو الطريق الذي يمكن أن يعيد لي جزءًا مما فقدته.\r\nورغم كل ما حدث، بقي في داخلي ذلك الحنين…\r\nحنين إلى تلك الأيام، إلى الأماكن التي أحببتها، إلى التفاصيل البسيطة التي كانت تعني لي الكثير. ما زلت أحتفظ بذكرياتي هناك، وأفكر بها دائمًا.\r\nأتمنى أن أعود يومًا…\r\nلكن ليس كما خرجت، بل في وقتٍ أفضل، وقتٍ يحمل السلام بدل الخوف، والحياة بدل المعاناة.\r\nورغم أن كل شيء تغيّر،\r\nإلا أن الأمل ما زال موجودًا…\r\nأمل بأن تعود الأيام الجميلة، وأن تصبح تلك الذكريات بدايةً لمرحلة أجمل.', '1776504364_noura.png');

